/* eslint-disable */
var addSorting = (function() {
    'use strict';
    var cols,
        currentSort = {
            index: 0,
            desc: false
        };

    // returns the summary table element
    function getTable() {
        return document.querySelector('.coverage-summary');
    }
    // returns the thead element of the summary table
    function getTableHeader() {
        return getTable().querySelector('thead tr');
    }
    // returns the tbody element of the summary table
    function getTableBody() {
        return getTable().querySelector('tbody');
    }
    // returns the th element for nth column
    function getNthColumn(n) {
        return getTableHeader().querySelectorAll('th')[n];
    }

    function onFilterInput() {
        const searchValue = document.getElementById('fileSearch').value;
        const rows = document.getElementsByTagName('tbody')[0].children;

        // Try to create a RegExp from the searchValue. If it fails (invalid regex),
        // it will be treated as a plain text search
        let searchRegex;
        try {
            searchRegex = new RegExp(searchValue, 'i'); // 'i' for case-insensitive
        } catch (error) {
            searchRegex = null;
        }

        for (let i = 0; i < rows.length; i++) {
            const row = rows[i];
            let isMatch = false;

            if (searchRegex) {
                // If a valid regex was created, use it for matching
                isMatch = searchRegex.test(row.textContent);
            } else {
                // Otherwise, fall back to the original plain text search
                isMatch = row.textContent
                    .toLowerCase()
                    .includes(searchValue.toLowerCase());
            }

            row.style.display = isMatch ? '' : 'none';
        }
    }

    // loads the search box
    function addSearchBox() {
        var template = document.getElementById('filterTemplate');
        var templateClone = template.content.cloneNode(true);
        templateClone.getElementById('fileSearch').oninput = onFilterInput;
        template.parentElement.appendChild(templateClone);
    }

    // loads all columns
    function loadColumns() {
        var colNodes = getTableHeader().querySelectorAll('th'),
            colNode,
            cols = [],
            col,
            i;

        for (i = 0; i < colNodes.length; i += 1) {
            colNode = colNodes[i];
            col = {
                key: colNode.getAttribute('data-col'),
                sortable: !colNode.getAttribute('data-nosort'),
                type: colNode.getAttribute('data-type') || 'string'
            };
            cols.push(col);
            if (col.sortable) {
                col.defaultDescSort = col.type === 'number';
                colNode.innerHTML =
                    colNode.innerHTML + '<span class="sorter"></span>';
            }
        }
        return cols;
    }
    // attaches a data attribute to every tr element with an object
    // of data values keyed by column name
    function loadRowData(tableRow) {
        var tableCols = tableRow.querySelectorAll('td'),
            colNode,
            col,
            data = {},
            i,
            val;
        for (i = 0; i < tableCols.length; i += 1) {
            colNode = tableCols[i];
            col = cols[i];
            val = colNode.getAttribute('data-value');
            if (col.type === 'number') {
                val = Number(val);
            }
            data[col.key] = val;
        }
        return data;
    }
    // loads all row data
    function loadData() {
        var rows = getTableBody().querySelectorAll('tr'),
            i;

        for (i = 0; i < rows.length; i += 1) {
            rows[i].data = loadRowData(rows[i]);
        }
    }
    // sorts the table using the data for the ith column
    function sortByIndex(index, desc) {
        var key = cols[index].key,
            sorter = function(a, b) {
                a = a.data[key];
                b = b.data[key];
                return a < b ? -1 : a > b ? 1 : 0;
            },
            finalSorter = sorter,
            tableBody = document.querySelector('.coverage-summary tbody'),
            rowNodes = tableBody.querySelectorAll('tr'),
            rows = [],
            i;

        if (desc) {
            finalSorter = function(a, b) {
                return -1 * sorter(a, b);
            };
        }

        for (i = 0; i < rowNodes.length; i += 1) {
            rows.push(rowNodes[i]);
            tableBody.removeChild(rowNodes[i]);
        }

        rows.sort(finalSorter);

        for (i = 0; i < rows.length; i += 1) {
            tableBody.appendChild(rows[i]);
        }
    }
    // removes sort indicators for current column being sorted
    function removeSortIndicators() {
        var col = getNthColumn(currentSort.index),
            cls = col.className;

        cls = cls.replace(/ sorted$/, '').replace(/ sorted-desc$/, '');
        col.className = cls;
    }
    // adds sort indicators for current column being sorted
    function addSortIndicators() {
        getNthColumn(currentSort.index).className += currentSort.desc
            ? ' sorted-desc'
            : ' sorted';
    }
    // adds event listeners for all sorter widgets
    function enableUI() {
        var i,
            el,
            ithSorter = function ithSorter(i) {
                var col = cols[i];

                return function() {
                    var desc = col.defaultDescSort;

                    if (currentSort.index === i) {
                        desc = !currentSort.desc;
                    }
                    sortByIndex(i, desc);
                    removeSortIndicators();
                    currentSort.index = i;
                    currentSort.desc = desc;
                    addSortIndicators();
                };
            };
        for (i = 0; i < cols.length; i += 1) {
            if (cols[i].sortable) {
                // add the click event handler on the th so users
                // dont have to click on those tiny arrows
                el = getNthColumn(i).querySelector('.sorter').parentElement;
                if (el.addEventListener) {
                    el.addEventListener('click', ithSorter(i));
                } else {
                    el.attachEvent('onclick', ithSorter(i));
                }
            }
        }
    }
    // adds sorting functionality to the UI
    return function() {
        if (!getTable()) {
            return;
        }
        cols = loadColumns();
        loadData();
        addSearchBox();
        addSortIndicators();
        enableUI();
    };
})();

window.addEventListener('load', addSorting);

import { useState } from 'react';
import { Outlet, Link, useLocation } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import * as Icons from 'lucide-react';
import clsx from 'clsx';

const {
  LayoutDashboard, ShoppingBag, Settings, LogOut, Package,
  Zap, Users, Shield, Truck, CreditCard, Ticket, Mail, FileText,
  ChevronDown, ChevronRight, Plus, Tag, Plug, Repeat, Menu, X, Bell
} = Icons;

console.log('Icons loaded:', { Bell: !!Bell });


interface NavItem {
  icon: any;
  label: string;
  path?: string;
  children?: NavItem[];
}

export function DashboardLayout() {
  const { logout } = useAuth();
  const location = useLocation();
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [expanded, setExpanded] = useState<Record<string, boolean>>({
    'Produtos': true,
    'Configurações': true,
    'Marketing': true
  });

  const toggleExpand = (label: string) => {
    setExpanded(prev => ({ ...prev, [label]: !prev[label] }));
  };

  const closeSidebar = () => setSidebarOpen(false);

  const navItems: NavItem[] = [
    { icon: LayoutDashboard, label: 'Resumo', path: '/' },
    { icon: ShoppingBag, label: 'Pedidos', path: '/orders' },
    {
      icon: Package,
      label: 'Produtos',
      children: [
        { icon: Package, label: 'Listagem', path: '/products' },
        { icon: Plus, label: 'Novo Produto', path: '/products/new' },
        { icon: Tag, label: 'Categorias', path: '/categories' }
      ]
    },
    { icon: Zap, label: 'Automações & IA', path: '/automations' },
    {
      icon: Ticket,
      label: 'Marketing',
      children: [
        { icon: Mail, label: 'E-mail Marketing', path: '/marketing/email' },
        { icon: Icons.Heart, label: 'Ranking de Favoritos', path: '/marketing/favorites' },
        { icon: Ticket, label: 'Cupons', path: '/marketing/coupons' },
        { icon: Mail, label: 'Recuperação', path: '/marketing/abandoned-cart' },
      ]
    },
    {
      icon: Repeat,
      label: 'Assinaturas',
      path: '/subscriptions'
    },
    {
      icon: Settings,
      label: 'Configurações',
      children: [
        { icon: Zap, label: 'IA', path: '/settings/ai' },
        { icon: Plug, label: 'Integrações', path: '/settings/integrations' },
        { icon: Users, label: 'Clientes', path: '/settings/users' },
        { icon: Users, label: 'Equipe', path: '/settings/team' },
        { icon: Shield, label: 'Auditoria', path: '/settings/audit' },
        { icon: Truck, label: 'Frete', path: '/settings/shipping' },
        { icon: CreditCard, label: 'Pagamentos', path: '/settings/payment' },
        { icon: FileText, label: 'Documentos Fiscais', path: '/settings/fiscal' },
        { icon: Bell, label: 'Alerta de Estoque', path: '/settings/stock-alerts' },
      ]
    },
  ];

  const renderNavItem = (item: NavItem, depth = 0) => {
    const Icon = item.icon;

    if (item.children) {
      const isExpanded = expanded[item.label];
      const isChildActive = item.children.some(child => child.path && location.pathname.startsWith(child.path));

      return (
        <div key={item.label}>
          <button
            onClick={() => toggleExpand(item.label)}
            className={clsx(
              "w-full flex items-center justify-between px-4 py-3 text-sm font-medium rounded-lg transition-colors",
              isChildActive ? "text-indigo-700 bg-indigo-50/50" : "text-gray-700 hover:bg-gray-50"
            )}
          >
            <div className="flex items-center">
              <Icon className="w-5 h-5 mr-3" />
              {item.label}
            </div>
            {isExpanded ? <ChevronDown size={16} /> : <ChevronRight size={16} />}
          </button>

          {isExpanded && (
            <div className="ml-4 border-l-2 border-gray-100 pl-2 space-y-1 mt-1">
              {item.children.map(child => renderNavItem(child, depth + 1))}
            </div>
          )}
        </div>
      );
    }

    const isActive = item.path === location.pathname;
    return (
      <Link
        key={item.path}
        to={item.path!}
        onClick={closeSidebar}
        className={clsx(
          "flex items-center px-4 py-2 text-sm font-medium rounded-lg transition-colors",
          isActive
            ? "bg-indigo-50 text-indigo-700"
            : "text-gray-700 hover:bg-gray-50"
        )}
      >
        <Icon className="w-5 h-5 mr-3" />
        {item.label}
      </Link>
    );
  };

  const sidebarContent = (
    <>
      <nav className="flex-1 p-4 space-y-1 overflow-y-auto">
        {navItems.map(item => renderNavItem(item))}
      </nav>

      <div className="p-4 border-t">
        <button
          onClick={logout}
          className="flex items-center w-full px-4 py-2 text-sm text-red-600 hover:bg-red-50 rounded-lg"
        >
          <LogOut className="w-5 h-5 mr-3" />
          Sair
        </button>
      </div>
    </>
  );

  return (
    <div className="flex h-screen bg-gray-100">
      {/* Mobile Header */}
      <div className="fixed top-0 left-0 right-0 z-40 bg-white border-b shadow-sm flex items-center justify-between px-4 h-14 md:hidden">
        <button
          onClick={() => setSidebarOpen(true)}
          className="p-2 rounded-lg text-gray-600 hover:bg-gray-100 transition"
          aria-label="Abrir menu"
        >
          <Menu size={24} />
        </button>
        <span className="font-semibold text-gray-800">Painel Admin</span>
        <div className="w-10" /> {/* Spacer para centralizar título */}
      </div>

      {/* Mobile Overlay */}
      {sidebarOpen && (
        <div
          className="fixed inset-0 z-40 bg-black/40 backdrop-blur-sm md:hidden"
          onClick={closeSidebar}
        />
      )}

      {/* Sidebar Desktop — sempre visível em md+ */}
      <aside className="hidden md:flex md:w-64 bg-white shadow-md flex-col flex-shrink-0">
        {sidebarContent}
      </aside>

      {/* Mobile Drawer */}
      <aside
        className={clsx(
          "fixed inset-y-0 left-0 w-72 bg-white shadow-xl flex flex-col z-50 transition-transform duration-300 md:hidden",
          sidebarOpen ? "translate-x-0" : "-translate-x-full"
        )}
      >
        {/* Mobile close button */}
        <div className="flex items-center justify-between p-4 border-b">
          <span className="font-semibold text-gray-800">Menu</span>
          <button
            onClick={closeSidebar}
            className="p-1 rounded-lg text-gray-500 hover:bg-gray-100 transition"
            aria-label="Fechar menu"
          >
            <X size={20} />
          </button>
        </div>

        {sidebarContent}
      </aside>

      {/* Main Content */}
      <main className="flex-1 overflow-auto p-4 pt-18 md:p-8 md:pt-8">
        <div className="max-w-7xl mx-auto">
          <Outlet />
        </div>
      </main>
    </div>
  );
}

import CreatableSelect from 'react-select/creatable';
import type { Category } from '../../types/category';

interface CreatableCategorySelectProps {
    categories: Category[];
    value: string;
    onChange: (value: string, newCategoryName?: string) => void;
    error?: string;
}

export function CreatableCategorySelect({ categories, value, onChange, error }: CreatableCategorySelectProps) {
    // Map our categories to react-select options format
    const options = categories.map((cat) => ({
        value: cat.id,
        label: cat.name,
        isNew: false
    }));

    // Find the selected option. If it's a new category (starts with NEW_), construct a temporary option
    const selectedOption = value?.startsWith('NEW_')
        ? { value, label: value.replace('NEW_', ''), isNew: true }
        : options.find((opt) => opt.value === value) || null;

    const handleChange = (newValue: any) => {
        if (!newValue) {
            onChange('');
            return;
        }

        if (newValue.__isNew__) {
            // The user created a new category (transient)
            onChange(`NEW_${newValue.label}`, newValue.label);
        } else {
            // The user selected an existing category
            onChange(newValue.value);
        }
    };

    // Rule: Only allow creating a new category if the typed name has at least 3 characters
    // and it doesn't already exist in the options list
    const isValidNewOption = (inputValue: string, _selectValue: any, selectOptions: readonly any[]) => {
        if (inputValue.trim().length < 3) return false;
        const exactMatch = selectOptions.some(
            (opt) => opt.label.toLowerCase() === inputValue.trim().toLowerCase()
        );
        return !exactMatch;
    };

    return (
        <div className="w-full">
            <CreatableSelect
                isClearable
                options={options}
                value={selectedOption}
                onChange={handleChange as any}
                isValidNewOption={isValidNewOption}
                formatCreateLabel={(inputValue) => `Adicionar "${inputValue}"`}
                placeholder="Selecione ou digite para adicionar uma categoria..."
                noOptionsMessage={({ inputValue }) =>
                    inputValue.length < 3
                        ? "Digite 3 ou mais letras para ver opções ou criar"
                        : "Nenhuma categoria existente encontrada."
                }
                styles={{
                    control: (base, state) => ({
                        ...base,
                        borderColor: error ? '#ef4444' : state.isFocused ? '#6366f1' : '#e5e7eb',
                        boxShadow: state.isFocused ? (error ? '0 0 0 1px #ef4444' : '0 0 0 1px #6366f1') : 'none',
                        '&:hover': {
                            borderColor: error ? '#ef4444' : state.isFocused ? '#6366f1' : '#d1d5db',
                        },
                        padding: '2px',
                        borderRadius: '0.5rem',
                        backgroundColor: 'white'
                    })
                }}
            />
            {error && <p className="text-red-500 text-xs mt-1">{error}</p>}
        </div>
    );
}

import { useState, useRef } from 'react';
import { Upload, X, Wand2 } from 'lucide-react';
import { ComingSoonModal } from '../ui/ComingSoonModal';
import type { ProductMedia } from '../../types/product';
import { getImageUrl } from '../../utils/imageUtils';

interface MediaGalleryProps {
    media: ProductMedia[];
    onChange: (media: ProductMedia[]) => void;
}

export function MediaGallery({ media, onChange }: MediaGalleryProps) {
    const [showComingSoon, setShowComingSoon] = useState(false);
    const fileInputRef = useRef<HTMLInputElement>(null);

    const handleUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files) {
            const newMediaItems: ProductMedia[] = [];

            for (const file of e.target.files) {
                const isVideo = file.type.startsWith('video/');
                const localUrl = URL.createObjectURL(file);

                newMediaItems.push({
                    id: crypto.randomUUID(),
                    url: localUrl,
                    type: isVideo ? 'VIDEO' : 'IMAGE',
                    isMain: media.length === 0 && !isVideo,
                    file: file
                } as any);
            }

            if (newMediaItems.length > 0) {
                onChange([...media, ...newMediaItems]);
            }

            // Resetar o valor do input para permitir selecionar o mesmo arquivo novamente
            if (fileInputRef.current) {
                fileInputRef.current.value = '';
            }
        }
    };

    const removeMedia = (id: string) => {
        onChange(media.filter(m => m.id !== id));
    };

    const setMain = (id: string) => {
        onChange(media.map(m => ({ ...m, isMain: m.id === id })));
    };

    const handleMagicRemoveBg = async (_id: string) => {
        setShowComingSoon(true);
    };

    return (
        <div className="space-y-4">
            <h3 className="font-semibold text-gray-700">Galeria de Mídia</h3>

            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                {/* Upload Button */}
                <label className="border-2 border-dashed border-gray-300 rounded-lg flex flex-col items-center justify-center h-40 cursor-pointer hover:border-indigo-500 hover:bg-indigo-50 transition relative">
                    <div className="text-center w-full px-4">
                        <Upload className="text-gray-400 mb-2 mx-auto" />
                        <span className="text-sm text-gray-500 block">Upload Arquivo</span>
                    </div>
                    <input
                        type="file"
                        ref={fileInputRef}
                        multiple
                        className="hidden"
                        accept="image/*,video/*"
                        onChange={handleUpload}
                    />
                </label>


                {/* Media List */}
                {media.map(item => (
                    <div key={item.id} className="relative group rounded-lg overflow-hidden border h-40 bg-gray-100">
                        {item.type === 'VIDEO' || (item.url && (item.url.endsWith('.mp4') || item.url.endsWith('.webm'))) ? (
                            <video
                                src={getImageUrl(item.url)}
                                className="w-full h-full object-cover"
                                controls
                            />
                        ) : (
                            <img
                                src={getImageUrl(item.url)}
                                alt="Media Preview"
                                className="w-full h-full object-cover"
                                onError={(e) => {
                                    (e.target as HTMLImageElement).src = 'https://placehold.co/400x400?text=Erro+Imagem';
                                }}
                            />
                        )}

                        {/* Overlay Actions */}
                        <div className="absolute inset-0 bg-black/50 opacity-0 group-hover:opacity-100 transition-opacity flex flex-col justify-between p-2 pointer-events-none group-hover:pointer-events-auto">
                            <div className="flex justify-end">
                                <button type="button" onClick={() => removeMedia(item.id)} className="text-white hover:text-red-400 z-10">
                                    <X size={16} />
                                </button>
                            </div>
                            <div className="flex gap-2">
                                {item.type === 'IMAGE' && (
                                    <>
                                        <button
                                            type="button"
                                            onClick={() => setMain(item.id)}
                                            className={`text-xs px-2 py-1 rounded ${item.isMain ? 'bg-indigo-600 text-white' : 'bg-white/20 text-white hover:bg-white/40'}`}
                                        >
                                            {item.isMain ? 'Capa' : 'Definir Capa'}
                                        </button>
                                        <button
                                            type="button"
                                            onClick={() => handleMagicRemoveBg(item.id)}
                                            title="Remover Fundo (IA)"
                                            className="bg-purple-600 text-white p-1 rounded hover:bg-purple-700"
                                        >
                                            <Wand2 size={14} />
                                        </button>
                                    </>
                                )}
                            </div>
                        </div>
                    </div>
                ))}
            </div>

            <ComingSoonModal
                isOpen={showComingSoon}
                onClose={() => setShowComingSoon(false)}
                title="Remoção de Fundo com IA"
                message="Essa funcionalidade será liberada em uma atualização futura. Em breve você poderá remover o fundo das suas imagens com apenas um clique!"
            />
        </div>
    );
}

