import { useState, useEffect } from 'react';
import { Shield, MapPin, Truck, Plus, Trash2, Info } from 'lucide-react';

interface MelhorEnvioConfigProps {
    config: any;
    onChange: (newConfig: any) => void;
}

const CARRIER_CATALOG = [
    { id: 'PAC', name: 'Correios PAC' },
    { id: 'SEDEX', name: 'Correios SEDEX' },
    { id: 'Jadlog .Package', name: 'Jadlog .Package' },
    { id: 'Jadlog .Com', name: 'Jadlog .Com' },
    { id: 'Azul Cargo', name: 'Azul Cargo' },
    { id: 'Latam Cargo', name: 'Latam Cargo' },
    { id: 'Loggi', name: 'Loggi' }
];

const UF_LIST = ['AC', 'AL', 'AP', 'AM', 'BA', 'CE', 'DF', 'ES', 'GO', 'MA', 'MT', 'MS', 'MG', 'PA', 'PB', 'PR', 'PE', 'PI', 'RJ', 'RN', 'RS', 'RO', 'RR', 'SC', 'SP', 'SE', 'TO'];

export function MelhorEnvioConfig({ config, onChange }: MelhorEnvioConfigProps) {
    const [token, setToken] = useState(config.token || '');
    const [zipCode, setZipCode] = useState(config.zipCode || '');
    const [allowedCarriers, setAllowedCarriers] = useState<string[]>(config.allowedCarriers || []);
    const [rules, setRules] = useState<any[]>(parseRules(config.rules || {}));

    function parseRules(rulesObj: any) {
        return Object.entries(rulesObj).map(([name, spel]: [string, any]) => {
            // Regex simples para extrair UF e Valor de: region == 'SP' and total >= 200
            const stateMatch = spel.match(/region\s*==\s*'([^']*)'/);
            const totalMatch = spel.match(/total\s*>=\s*([\d.]+)/);
            const minAmount = totalMatch ? totalMatch[1] : '';
            return {
                id: Math.random().toString(36).substr(2, 9),
                name,
                state: stateMatch ? stateMatch[1] : 'TODOS',
                minAmount: minAmount === '0' ? '' : minAmount
            };
        });
    }

    function generateSpel(rule: any) {
        let parts = [];
        if (rule.state !== 'TODOS') parts.push(`region == '${rule.state}'`);
        const amount = parseFloat(rule.minAmount || '0');
        if (amount > 0) parts.push(`total >= ${amount}`);
        return parts.length > 0 ? parts.join(' and ') : 'true';
    }

    useEffect(() => {
        const rulesObj: any = {};
        rules.forEach(r => {
            rulesObj[r.name] = generateSpel(r);
        });

        onChange({
            token,
            zipCode,
            allowedCarriers,
            rules: rulesObj
        });
    }, [token, zipCode, allowedCarriers, rules]);

    const handleCarrierToggle = (id: string) => {
        setAllowedCarriers(prev =>
            prev.includes(id) ? prev.filter(c => c !== id) : [...prev, id]
        );
    };

    const addRule = () => {
        setRules(prev => [...prev, {
            id: Math.random().toString(36).substr(2, 9),
            name: `Regra ${prev.length + 1}`,
            state: 'TODOS',
            minAmount: ''
        }]);
    };

    const removeRule = (id: string) => {
        setRules(prev => prev.filter(r => r.id !== id));
    };

    const updateRule = (id: string, field: string, value: any) => {
        setRules(prev => prev.map(r => r.id === id ? { ...r, [field]: value } : r));
    };

    return (
        <div className="space-y-8 animate-in fade-in duration-500">
            {/* Credenciais */}
            <section className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm space-y-4">
                <div className="flex items-center gap-2 text-indigo-600 font-bold mb-2">
                    <Shield size={20} />
                    <h2>Credenciais e Origem</h2>
                </div>
                <div className="grid md:grid-cols-2 gap-4">
                    <div className="space-y-1">
                        <label className="text-xs font-bold text-gray-500 uppercase tracking-wider">Token de API</label>
                        <input
                            type="password"
                            value={token}
                            onChange={(e) => setToken(e.target.value)}
                            className="w-full border p-3 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                            placeholder="Insira seu Token do Melhor Envio"
                        />
                    </div>
                    <div className="space-y-1">
                        <label className="text-xs font-bold text-gray-500 uppercase tracking-wider">CEP de Origem</label>
                        <div className="relative">
                            <MapPin className="absolute left-3 top-3.5 text-gray-400" size={18} />
                            <input
                                type="text"
                                value={zipCode}
                                onChange={(e) => setZipCode(e.target.value)}
                                className="w-full border p-3 pl-10 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                                placeholder="00000-000"
                            />
                        </div>
                    </div>
                </div>
            </section>

            {/* Transportadoras */}
            <section className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm space-y-4">
                <div className="flex items-center gap-2 text-indigo-600 font-bold mb-2">
                    <Truck size={20} />
                    <h2>Transportadoras Ativas</h2>
                </div>
                <p className="text-sm text-gray-500">Selecione quais serviços do Melhor Envio você deseja oferecer no checkout.</p>
                <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-3">
                    {CARRIER_CATALOG.map(carrier => (
                        <button
                            key={carrier.id}
                            onClick={() => handleCarrierToggle(carrier.id)}
                            className={`flex items-center justify-between p-3 rounded-xl border-2 transition-all font-medium text-sm ${allowedCarriers.includes(carrier.id)
                                ? 'border-indigo-500 bg-indigo-50 text-indigo-700'
                                : 'border-gray-50 bg-gray-50 text-gray-400 hover:border-gray-200'
                                }`}
                        >
                            {carrier.name}
                            {allowedCarriers.includes(carrier.id) && <div className="w-2 h-2 bg-indigo-600 rounded-full animate-pulse" />}
                        </button>
                    ))}
                </div>
            </section>

            {/* Regras de Frete Grátis */}
            <section className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm space-y-4">
                <div className="flex items-center justify-between">
                    <div className="flex items-center gap-2 text-green-600 font-bold">
                        <Plus size={20} />
                        <h2>Regras de Frete Grátis</h2>
                    </div>
                    <button
                        onClick={addRule}
                        className="bg-green-50 text-green-600 px-4 py-2 rounded-xl text-sm font-bold hover:bg-green-100 transition flex items-center gap-2"
                    >
                        Nova Regra
                    </button>
                </div>

                <div className="space-y-3">
                    {rules.length === 0 && (
                        <div className="text-center py-8 bg-gray-50 rounded-2xl border border-dashed border-gray-200">
                            <Info className="mx-auto text-gray-300 mb-2" size={32} />
                            <p className="text-sm text-gray-400 font-medium">Nenhuma regra de frete grátis configurada.</p>
                        </div>
                    )}

                    {rules.map(rule => (
                        <div key={rule.id} className="grid md:grid-cols-4 gap-3 p-4 bg-gray-50 rounded-2xl border border-gray-100 items-end animate-in slide-in-from-left duration-300">
                            <div className="space-y-1">
                                <label className="text-[10px] font-bold text-gray-400 uppercase">Nome da Regra</label>
                                <input
                                    type="text"
                                    value={rule.name}
                                    onChange={(e) => updateRule(rule.id, 'name', e.target.value)}
                                    className="w-full border p-2 rounded-lg text-sm bg-white"
                                />
                            </div>
                            <div className="space-y-1">
                                <label className="text-[10px] font-bold text-gray-400 uppercase">Estado (UF)</label>
                                <select
                                    value={rule.state}
                                    onChange={(e) => updateRule(rule.id, 'state', e.target.value)}
                                    className="w-full border p-2 rounded-lg text-sm bg-white"
                                >
                                    <option value="TODOS">Todos os Estados</option>
                                    {UF_LIST.map(uf => <option key={uf} value={uf}>{uf}</option>)}
                                </select>
                            </div>
                            <div className="space-y-1">
                                <label className="text-[10px] font-bold text-gray-400 uppercase">Valor Mínimo (R$)</label>
                                <input
                                    type="number"
                                    value={rule.minAmount}
                                    placeholder="0"
                                    onChange={(e) => updateRule(rule.id, 'minAmount', e.target.value)}
                                    className="w-full border p-2 rounded-lg text-sm bg-white"
                                />
                            </div>
                            <div className="flex justify-end">
                                <button
                                    onClick={() => removeRule(rule.id)}
                                    className="p-2 text-red-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition"
                                >
                                    <Trash2 size={20} />
                                </button>
                            </div>
                        </div>
                    ))}
                </div>
            </section>
        </div>
    );
}

import { createContext, useContext, useState, type ReactNode, useEffect } from 'react';
import { api } from '../api/axios';

interface AuthContextType {
  isAuthenticated: boolean;
  login: (token: string) => void;
  logout: () => void;
  isLoading: boolean;
}

const AuthContext = createContext<AuthContextType>({} as AuthContextType);

export function AuthProvider({ children }: { children: ReactNode }) {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    const validateToken = async () => {
      const token = localStorage.getItem('auth_token');
      if (!token) {
        setIsLoading(false);
        return;
      }

      try {
        // Tenta bater num endpoint leve para ver se o token é válido e o back está vivo
        // Se der erro de rede, cai no catch e desloga
        await api.get('/health');
        setIsAuthenticated(true);
      } catch (error) {
        console.error("Sessão inválida ou Backend offline:", error);
        localStorage.removeItem('auth_token');
        setIsAuthenticated(false);
      } finally {
        setIsLoading(false);
      }
    };

    validateToken();
  }, []);

  const login = (token: string) => {
    localStorage.setItem('auth_token', token);
    setIsAuthenticated(true);
  };

  const logout = () => {
    localStorage.removeItem('auth_token');
    setIsAuthenticated(false);
    window.location.href = '/login';
  };

  return (
    <AuthContext.Provider value={{ isAuthenticated, login, logout, isLoading }}>
      {children}
    </AuthContext.Provider>
  );
}

export const useAuth = () => useContext(AuthContext);

import React, { createContext, useContext, useState, useEffect } from 'react';
import nprogress from 'nprogress';
import 'nprogress/nprogress.css';

// Configuração do NProgress
nprogress.configure({
    showSpinner: false,
    trickleSpeed: 200,
    minimum: 0.1
});

interface LoadingContextType {
    isGlobalLoading: boolean;
}

const LoadingContext = createContext<LoadingContextType | undefined>(undefined);

// Listeners externos para o Axios
let updateIsGlobalLoading: (val: boolean) => void = () => { };

export const startLoading = (isGlobal = false) => {
    nprogress.start();
    if (isGlobal) {
        updateIsGlobalLoading(true);
    }
};

export const stopLoading = () => {
    nprogress.done();
    updateIsGlobalLoading(false);
};

export const LoadingProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const [isGlobalLoading, setIsGlobalLoading] = useState(false);

    useEffect(() => {
        updateIsGlobalLoading = setIsGlobalLoading;
    }, []);

    return (
        <LoadingContext.Provider value={{ isGlobalLoading }}>
            {children}
        </LoadingContext.Provider>
    );
};

export const useLoading = () => {
    const context = useContext(LoadingContext);
    if (!context) {
        throw new Error('useLoading must be used within a LoadingProvider');
    }
    return context;
};

import { createContext, useContext, useState, useEffect, type ReactNode } from 'react';
import type { Tenant } from '../types/tenant';
import { TenantService } from '../services/TenantService';
import { api } from '../api/axios';

interface TenantContextType {
    currentTenant: Tenant | null;
    tenants: Tenant[];
    isLoading: boolean;
    switchTenant: (tenantId: string) => void;
    refreshTenants: () => Promise<void>;
}

const TenantContext = createContext<TenantContextType>({} as TenantContextType);

export function TenantProvider({ children }: { children: ReactNode }) {
    const [tenants, setTenants] = useState<Tenant[]>([]);
    const [currentTenant, setCurrentTenant] = useState<Tenant | null>(null);
    const [isLoading, setIsLoading] = useState(true);

    useEffect(() => {
        loadTenants();
    }, []);

    const loadTenants = async () => {
        try {
            const data = await TenantService.getAll();
            setTenants(data);

            // Restaurar seleção anterior ou selecionar o primeiro
            const savedId = localStorage.getItem('current_tenant_id');
            const selected = data.find(t => t.id === savedId) || data[0];

            if (selected) {
                selectTenant(selected);
            }
        } catch (error) {
            console.error('Failed to load tenants', error);
        } finally {
            setIsLoading(false);
        }
    };

    const selectTenant = (tenant: Tenant) => {
        setCurrentTenant(tenant);
        localStorage.setItem('current_tenant_id', tenant.id);
        // Configurar header global para futuras requisições
        api.defaults.headers.common['X-Tenant-ID'] = tenant.id;
    };

    const switchTenant = (tenantId: string) => {
        const tenant = tenants.find(t => t.id === tenantId);
        if (tenant) {
            selectTenant(tenant);
            // Opcional: Recarregar a página para limpar estados antigos de produtos/pedidos
            window.location.reload();
        }
    };

    return (
        <TenantContext.Provider value={{ currentTenant, tenants, isLoading, switchTenant, refreshTenants: loadTenants }}>
            {children}
        </TenantContext.Provider>
    );
}

export const useTenant = () => useContext(TenantContext);

import React, { createContext, useContext, useState, useCallback } from 'react';
import { X, CheckCircle, AlertCircle, Info } from 'lucide-react';

type ToastType = 'success' | 'error' | 'info';

interface Toast {
    id: string;
    message: string;
    type: ToastType;
}

interface ToastContextData {
    addToast: (message: string, type?: ToastType) => void;
}

const ToastContext = createContext<ToastContextData>({} as ToastContextData);

export const ToastProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const [toasts, setToasts] = useState<Toast[]>([]);

    const addToast = useCallback((message: string, type: ToastType = 'info') => {
        const id = Math.random().toString(36).substr(2, 9);
        setToasts((prev) => [...prev, { id, message, type }]);

        setTimeout(() => {
            setToasts((prev) => prev.filter((t) => t.id !== id));
        }, 5000);
    }, []);

    const removeToast = (id: string) => {
        setToasts((prev) => prev.filter((t) => t.id !== id));
    };

    return (
        <ToastContext.Provider value={{ addToast }}>
            {children}
            <div className="fixed bottom-4 right-4 z-[9999] flex flex-col gap-2 pointer-events-none">
                {toasts.map((toast) => (
                    <div
                        key={toast.id}
                        className={`
              pointer-events-auto flex items-center gap-3 px-4 py-3 rounded-lg shadow-xl border min-w-[300px] animate-in slide-in-from-right fade-in duration-300
              ${toast.type === 'success' ? 'bg-emerald-50 border-emerald-200 text-emerald-800' : ''}
              ${toast.type === 'error' ? 'bg-red-50 border-red-200 text-red-800' : ''}
              ${toast.type === 'info' ? 'bg-indigo-50 border-indigo-200 text-indigo-800' : ''}
            `}
                    >
                        {toast.type === 'success' && <CheckCircle size={18} className="text-emerald-500" />}
                        {toast.type === 'error' && <AlertCircle size={18} className="text-red-500" />}
                        {toast.type === 'info' && <Info size={18} className="text-indigo-500" />}

                        <span className="flex-1 text-sm font-medium">{toast.message}</span>

                        <button
                            onClick={() => removeToast(toast.id)}
                            className="p-1 hover:bg-black/5 rounded-full transition-colors"
                        >
                            <X size={14} />
                        </button>
                    </div>
                ))}
            </div>
        </ToastContext.Provider>
    );
};

export const useToast = () => {
    const context = useContext(ToastContext);
    if (!context) {
        throw new Error('useToast must be used within a ToastProvider');
    }
    return context;
};

import { useState, useEffect, useCallback, useMemo } from 'react';
import { StockAlertService, type StockAlertSettings, type StockPriority } from '../services/StockAlertService';
import { ProductService } from '../services/ProductService';
import type { Product } from '../types/product';

export const STOCK_COLORS = {
    red: { label: 'Crítico', bg: 'bg-red-100', text: 'text-red-700', border: 'border-red-200' },
    amber: { label: 'Atenção', bg: 'bg-amber-100', text: 'text-amber-700', border: 'border-amber-200' },
    blue: { label: 'Informativo', bg: 'bg-blue-100', text: 'text-blue-700', border: 'border-blue-200' },
    indigo: { label: 'Preferencial', bg: 'bg-indigo-100', text: 'text-indigo-700', border: 'border-indigo-200' },
} as const;

export type ColorPreset = keyof typeof STOCK_COLORS;

/**
 * Calcula a prioridade de um produto com base no estoque e configurações.
 * Exportado para reuso em outros componentes (ex: ProductsPage).
 */
export const calculatePriority = (stock: number, settings: StockAlertSettings | null) => {
    if (!settings) return null;

    // Encontrar a prioridade correspondente (menor maxLevel primeiro)
    return [...settings.priorities]
        .sort((a, b) => a.maxLevel - b.maxLevel)
        .find(pr => stock <= pr.maxLevel) || null;
};

export function useStockAlerts() {
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);
    const [success, setSuccess] = useState(false);
    const [settings, setSettings] = useState<StockAlertSettings | null>(null);
    const [products, setProducts] = useState<Product[]>([]);

    const loadData = useCallback(async () => {
        setLoading(true);
        try {
            const [alertSettings, allProducts] = await Promise.all([
                StockAlertService.getSettings(),
                ProductService.getAll()
            ]);
            setSettings(alertSettings);
            setProducts(allProducts);
        } catch (error) {
            console.error('Erro ao carregar alertas:', error);
        } finally {
            setLoading(false);
        }
    }, []);

    useEffect(() => {
        loadData();
    }, [loadData]);

    const saveSettings = async () => {
        if (!settings) return;
        setSaving(true);
        setSuccess(false);
        try {
            await StockAlertService.saveSettings(settings);
            setSuccess(true);
            setTimeout(() => setSuccess(false), 3000);
        } catch (error) {
            console.error('Erro ao salvar:', error);
            throw error;
        } finally {
            setSaving(false);
        }
    };

    const updateThreshold = (threshold: number) => {
        if (!settings) return;
        setSettings({ ...settings, threshold });
    };

    const updateTemplate = (messageTemplate: string) => {
        if (!settings) return;
        setSettings({ ...settings, messageTemplate });
    };

    const addPriority = () => {
        if (!settings) return;
        const newPriority: StockPriority = {
            label: 'Novo Nível',
            maxLevel: 5,
            color: 'red' // Default preset
        };
        setSettings({ ...settings, priorities: [...settings.priorities, newPriority] });
    };

    const removePriority = (index: number) => {
        if (!settings) return;
        setSettings({
            ...settings,
            priorities: settings.priorities.filter((_, i) => i !== index)
        });
    };

    const updatePriority = (index: number, field: keyof StockPriority, value: any) => {
        if (!settings) return;
        const newPriorities = [...settings.priorities];
        newPriorities[index] = { ...newPriorities[index], [field]: value };
        setSettings({ ...settings, priorities: newPriorities });
    };

    const lowStockProducts = useMemo(() => {
        if (!settings) return [];

        return products
            .filter(p => (p.stock || 0) <= settings.threshold + 20)
            .map(p => ({
                ...p,
                currentPriority: calculatePriority(p.stock || 0, settings)
            }))
            .sort((a, b) => (a.stock || 0) - (b.stock || 0));
    }, [products, settings]);

    return {
        loading,
        saving,
        success,
        settings,
        lowStockProducts,
        updateThreshold,
        updateTemplate,
        addPriority,
        removePriority,
        updatePriority,
        saveSettings,
        refresh: loadData
    };
}

