import { useEffect, useState } from 'react';
import { Ticket, Plus, Trash2, ToggleLeft, ToggleRight, Edit2 } from 'lucide-react';
import { MarketingService } from '../../services/MarketingService';
import type { Coupon, CreateCouponDTO } from '../../types/marketing';
import { CouponModal } from './CouponModal';

export function CouponList() {
    const [coupons, setCoupons] = useState<Coupon[]>([]);
    const [loading, setLoading] = useState(true);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [selectedCoupon, setSelectedCoupon] = useState<Coupon | null>(null);

    useEffect(() => {
        loadCoupons();
    }, []);

    const loadCoupons = async () => {
        try {
            setLoading(true);
            const data = await MarketingService.getCoupons();
            setCoupons(data);
        } catch (error) {
            console.error('Erro ao carregar cupons', error);
        } finally {
            setLoading(false);
        }
    };

    const handleOpenCreate = () => {
        setSelectedCoupon(null);
        setIsModalOpen(true);
    };

    const handleOpenEdit = (coupon: Coupon) => {
        setSelectedCoupon(coupon);
        setIsModalOpen(true);
    };

    const handleSave = async (dto: CreateCouponDTO) => {
        if (selectedCoupon) {
            await MarketingService.updateCoupon(selectedCoupon.id, dto);
        } else {
            await MarketingService.createCoupon(dto);
        }
        await loadCoupons();
    };

    const handleToggle = async (id: string, currentStatus: boolean) => {
        try {
            await MarketingService.toggleCoupon(id, !currentStatus);
            setCoupons(prev => prev.map(c => c.id === id ? { ...c, active: !currentStatus } : c));
        } catch (err) {
            alert('Erro ao alterar status');
        }
    };

    const handleDelete = async (id: string) => {
        if (!confirm('Excluir este cupom?')) return;
        try {
            await MarketingService.deleteCoupon(id);
            setCoupons(prev => prev.filter(c => c.id !== id));
        } catch (err) {
            alert('Erro ao excluir');
        }
    };

    return (
        <div className="space-y-6">
            <div className="flex justify-between items-center">
                <div>
                    <h1 className="text-2xl font-bold text-gray-800">Cupons de Desconto</h1>
                    <p className="text-gray-500">Crie campanhas promocionais</p>
                </div>
                <button
                    onClick={handleOpenCreate}
                    className="flex items-center gap-2 bg-indigo-600 text-white px-4 py-2 rounded-lg hover:bg-indigo-700 transition"
                >
                    <Plus size={20} />
                    Criar Cupom
                </button>
            </div>

            <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
                {loading ? (
                    <div className="p-8 text-center text-gray-500">Carregando cupons...</div>
                ) : coupons.length === 0 ? (
                    <div className="p-12 text-center text-gray-400 flex flex-col items-center">
                        <Ticket size={48} className="mb-4 text-gray-200" />
                        <p>Nenhum cupom ativo no momento.</p>
                    </div>
                ) : (
                    <table className="w-full text-left">
                        <thead className="bg-gray-50 border-b">
                            <tr>
                                <th className="p-4 text-sm font-semibold text-gray-600">Código</th>
                                <th className="p-4 text-sm font-semibold text-gray-600">Desconto</th>
                                <th className="p-4 text-sm font-semibold text-gray-600">Usos</th>
                                <th className="p-4 text-sm font-semibold text-gray-600">Status</th>
                                <th className="p-4 text-sm font-semibold text-gray-600 text-right">Ações</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-100">
                            {coupons.length === 0 ? (
                                <tr>
                                    <td colSpan={5} className="p-8 text-center text-gray-500 italic">
                                        Nenhum cupom cadastrado.
                                    </td>
                                </tr>
                            ) : (
                                coupons.map((coupon) => (
                                    <tr key={coupon.id} className="hover:bg-gray-50 transition">
                                        <td className="p-4 font-mono font-bold text-indigo-700">{coupon.code}</td>
                                        <td className="p-4 text-gray-700">
                                            {coupon.type === 'PERCENTAGE' ? `${coupon.value}%` : `R$ ${coupon.value.toFixed(2)}`}
                                        </td>
                                        <td className="p-4 text-sm text-gray-500">
                                            {coupon.usageCount} {coupon.usageLimit ? `/ ${coupon.usageLimit}` : ''}
                                        </td>
                                        <td className="p-4">
                                            <button onClick={() => handleToggle(coupon.id, coupon.active)} className="text-indigo-600">
                                                {coupon.active ? <ToggleRight size={24} /> : <ToggleLeft size={24} className="text-gray-300" />}
                                            </button>
                                        </td>
                                        <td className="p-4 text-right">
                                            <div className="flex justify-end gap-2">
                                                <button
                                                    onClick={() => handleOpenEdit(coupon)}
                                                    className="p-1 text-gray-400 hover:text-indigo-600 transition"
                                                    title="Editar"
                                                >
                                                    <Edit2 size={18} />
                                                </button>
                                                <button
                                                    onClick={() => handleDelete(coupon.id)}
                                                    className="p-1 text-gray-400 hover:text-red-600 transition"
                                                    title="Excluir"
                                                >
                                                    <Trash2 size={18} />
                                                </button>
                                            </div>
                                        </td>
                                    </tr>
                                ))
                            )}
                        </tbody>
                    </table>
                )}
            </div>

            <CouponModal
                isOpen={isModalOpen}
                onClose={() => setIsModalOpen(false)}
                onSave={handleSave}
                initialData={selectedCoupon || undefined}
            />
        </div>
    );
}

import React, { useState } from 'react';
import type { CreateCouponDTO } from '../../types/marketing';
import BaseModal from '../../components/ui/BaseModal';
import Button from '../../components/ui/Button';
import { useToast } from '../../context/ToastContext';

interface CouponModalProps {
    isOpen: boolean;
    onClose: () => void;
    onSave: (coupon: CreateCouponDTO) => Promise<void>;
    initialData?: CreateCouponDTO;
}

export function CouponModal({ isOpen, onClose, onSave, initialData }: CouponModalProps) {
    const [formData, setFormData] = useState<CreateCouponDTO>({
        code: '',
        type: 'PERCENTAGE',
        value: 0,
        usageLimit: 100,
        usageLimitPerUser: 1,
        minPurchaseValue: 0
    });
    const { addToast } = useToast();
    const [loading, setLoading] = useState(false);

    React.useEffect(() => {
        if (initialData) {
            setFormData(initialData);
        } else {
            setFormData({
                code: '',
                type: 'PERCENTAGE',
                value: 0,
                usageLimit: 100,
                usageLimitPerUser: 1,
                minPurchaseValue: 0
            });
        }
    }, [initialData, isOpen]);

    if (!isOpen) return null;

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        try {
            setLoading(true);
            await onSave(formData);
            addToast(initialData ? 'Cupom atualizado com sucesso!' : 'Cupom criado com sucesso!', 'success');
            onClose();
        } catch (error) {
            addToast(initialData ? 'Erro ao atualizar cupom' : 'Erro ao criar cupom', 'error');
        } finally {
            setLoading(false);
        }
    };

    return (
        <BaseModal
            isOpen={isOpen}
            onClose={onClose}
            title={initialData ? 'Editar Cupom' : 'Novo Cupom'}
        >
            <form onSubmit={handleSubmit} className="space-y-4">
                <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Código do Cupom</label>
                    <input
                        required
                        type="text"
                        value={formData.code}
                        onChange={(e) => setFormData({ ...formData, code: e.target.value.toUpperCase() })}
                        placeholder="Ex: VERAS25"
                        className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none uppercase"
                    />
                </div>

                <div className="grid grid-cols-2 gap-4">
                    <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">Tipo</label>
                        <select
                            value={formData.type}
                            onChange={(e) => setFormData({ ...formData, type: e.target.value as any })}
                            className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                        >
                            <option value="PERCENTAGE">Porcentagem (%)</option>
                            <option value="FIXED">Valor Fixo (R$)</option>
                        </select>
                    </div>
                    <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">
                            {formData.type === 'PERCENTAGE' ? 'Porcentagem (%)' : 'Valor (R$)'}
                        </label>
                        <input
                            required
                            type="number"
                            step="0.01"
                            value={formData.value === 0 ? '' : formData.value}
                            onChange={(e) => setFormData({ ...formData, value: e.target.value === '' ? 0 : parseFloat(e.target.value) })}
                            placeholder={formData.type === 'PERCENTAGE' ? "10" : "50.00"}
                            className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                        />
                    </div>
                </div>

                <div className="grid grid-cols-2 gap-4">
                    <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">Limite Total</label>
                        <input
                            required
                            type="number"
                            value={formData.usageLimit === 0 ? '' : formData.usageLimit}
                            onChange={(e) => setFormData({ ...formData, usageLimit: e.target.value === '' ? 0 : parseInt(e.target.value) })}
                            placeholder="100"
                            className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                        />
                    </div>
                    <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">Limite por Usuário</label>
                        <input
                            required
                            type="number"
                            value={formData.usageLimitPerUser === 0 ? '' : formData.usageLimitPerUser}
                            onChange={(e) => setFormData({ ...formData, usageLimitPerUser: e.target.value === '' ? 0 : parseInt(e.target.value) })}
                            placeholder="1"
                            className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                        />
                    </div>
                </div>

                <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Valor Mínimo da Compra (R$)</label>
                    <input
                        type="number"
                        step="0.01"
                        value={formData.minPurchaseValue === 0 ? '' : formData.minPurchaseValue}
                        onChange={(e) => setFormData({ ...formData, minPurchaseValue: e.target.value === '' ? 0 : parseFloat(e.target.value) })}
                        placeholder="0.00"
                        className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                    />
                    <p className="mt-1 text-xs text-gray-500 italic">Deixe em branco ou digite 0 para ignorar o valor mínimo.</p>
                </div>

                <div className="flex gap-3 pt-4">
                    <Button
                        type="button"
                        onClick={onClose}
                        variant="secondary"
                        className="flex-1"
                    >
                        Cancelar
                    </Button>
                    <Button
                        isLoading={loading}
                        type="submit"
                        variant="primary"
                        className="flex-1"
                    >
                        {initialData ? 'Salvar Alterações' : 'Criar Cupom'}
                    </Button>
                </div>
            </form>
        </BaseModal>
    );
}

