    { name: 'SES', host: 'email-smtp.us-east-1.amazonaws.com', port: 587 },
    { name: 'Custom', host: '', port: 587 }
];

import { getImageUrl } from '../../utils/imageUtils';

export default function EmailMarketingHub() {
    const [activeTab, setActiveTab] = useState<'analytics' | 'design' | 'config'>('analytics');
    const [activeDesignSubTab, setActiveDesignSubTab] = useState<'templates' | 'signatures' | 'campaigns'>('templates');

    // --- State: Analytics ---
    const [metrics, setMetrics] = useState<EmailMetric>({ totalSent: 0, failed: 0, pending: 0, verifiedUsers: 0, totalNewsletter: 0 });
    const [queue, setQueue] = useState<EmailQueued[]>([]);
    const [loadingAnalytics, setLoadingAnalytics] = useState(true);
    const [queueFilter, setQueueFilter] = useState<string>('ALL');

    // --- State: Design (Templates) ---
    const [templates, setTemplates] = useState<EmailTemplate[]>([]);
    const [signatures, setSignatures] = useState<Signature[]>([]);
    const [editingTemplate, setEditingTemplate] = useState<EmailTemplate | null>(null);
    const [isSavingTemplate, setIsSavingTemplate] = useState(false);
    const [isCreatingTemplate, setIsCreatingTemplate] = useState(false);
    const [newTemplate, setNewTemplate] = useState({
        name: '',
        slug: '',
        subject: '',
        content: '',
        signatureId: null as string | null,
        active: true
    });

    // --- State: Campaigns ---
    const [campaigns, setCampaigns] = useState<EmailCampaign[]>([]);
    const [isCreatingCampaign, setIsCreatingCampaign] = useState(false);
    const [isSavingCampaign, setIsSavingCampaign] = useState(false);
    const [newCampaign, setNewCampaign] = useState<EmailCampaign>({
        name: '',
        subject: '',
        content: '',
        status: 'PENDING',
        totalRecipients: 0,
        sentCount: 0,
        audience: 'NEWSLETTER_SUBSCRIBERS',
        signatureId: null
    });

    // --- State: Design (Signatures) ---
    const [isSavingSignature, setIsSavingSignature] = useState(false);
    const [isUploading, setIsUploading] = useState(false);
    const [uploadProgress, setUploadProgress] = useState(0);
    const [selectedSignatureId, setSelectedSignatureId] = useState<string | null>(null);
    const [signatureForm, setSignatureForm] = useState<Signature>({
        name: 'Assinatura Principal',
        ownerName: '',
        role: 'Direção',
        storeName: 'Ateliê Filhos de Aruanda',
        whatsapp: '',
        email: '',
        storeUrl: 'https://www.atelie.com.br',
        logoUrl: 'https://via.placeholder.com/150',
        motto: 'Arte e Espiritualidade guiando nossos caminhos.'
    });

    // --- State: Config (SMTP) ---
    const [smtpConfig, setSmtpConfig] = useState<SMTPConfig>({
        id: '',
        mailHost: '',
        mailPort: 587,
        mailUsername: '',
        mailPassword: '',
        mailSenderAddress: '',
        mailSenderName: ''
    });
    const [isSavingSMTP, setIsSavingSMTP] = useState(false);
    const [showPassword, setShowPassword] = useState(false);

    // --- Utils ---
    const formatPhone = (value: string) => {
        if (!value) return value;
        const phone = value.replace(/\D/g, '');
        if (phone.length <= 10) {
            return phone.replace(/(\d{2})(\d{4})(\d{4})/, '($1) $2-$3');
        }
        return phone.replace(/(\d{2})(\d{5})(\d{4})/, '($1) $2-$3');
    };

    // --- Effects: Data Loading ---
    useEffect(() => {
        if (activeTab === 'analytics') loadAnalytics();
        if (activeTab === 'design') {
            loadDesignData();
            if (activeDesignSubTab === 'campaigns') loadCampaigns();
        }
        if (activeTab === 'config') loadSMTPConfigs();
    }, [activeTab, activeDesignSubTab]);

    useEffect(() => {
        const interval = setInterval(() => {
            if (activeTab === 'analytics') loadAnalytics(false);
        }, 30000);
        return () => clearInterval(interval);
    }, [activeTab]);

    // --- Logic: Analytics ---
    const loadAnalytics = async (showLoading = true) => {
        if (showLoading) setLoadingAnalytics(true);
        try {
            const [metricsRes, queueRes] = await Promise.all([
                api.get('/marketing/metrics'),
                api.get('/marketing/email-queue')
            ]);
            const rawMetrics = metricsRes.data;
            setMetrics({
                totalSent: rawMetrics.emailsSent || 0,
                failed: queueRes.data.filter((e: any) => e.status === 'FAILED').length,
                pending: queueRes.data.filter((e: any) => e.status === 'PENDING').length,
                verifiedUsers: rawMetrics.verifiedUsers || 0,
                totalNewsletter: rawMetrics.totalNewsletter || 0
            });
            setQueue(queueRes.data.reverse());
        } catch (error) {
            console.error('Error loading analytics:', error);
        } finally {
            setLoadingAnalytics(false);
        }
    };

    const handleRetryEmail = async (id: string) => {
        try {
            await api.post(`/marketing/email-queue/${id}/retry`);
            loadAnalytics(false);
        } catch (error) {
            console.error('Error retrying email:', error);
        }
    };

    const handleRetryAllFailed = async () => {
        if (!confirm('Deseja reenviar todos os e-mails com falha?')) return;
        try {
            await api.post('/marketing/email-queue/retry-failed');
            loadAnalytics(false);
        } catch (error) {
            console.error('Error retrying failed emails:', error);
        }
    };

    // --- Logic: Design (Templates) ---
    const loadDesignData = async () => {
        try {
            const [templatesRes, signaturesRes] = await Promise.all([
                api.get('/marketing/email-templates'),
                api.get('/marketing/signatures')
            ]);

            // Normalizar templates para evitar warnings de valor null em inputs controlados
            const normalizedTemplates = templatesRes.data.map((t: any) => ({
                ...t,
                name: t.name || '',
                subject: t.subject || '',
                content: t.content || '',
                automationType: t.automationType || ''
            }));

            // Normalizar assinaturas
            const normalizedSignatures = signaturesRes.data.map((s: any) => ({
                ...s,
                ownerName: s.ownerName || '',
                role: s.role || '',
                storeName: s.storeName || '',
                whatsapp: s.whatsapp || '',
                email: s.email || '',
                storeUrl: s.storeUrl || '',
                logoUrl: s.logoUrl || '',
                motto: s.motto || ''
            }));

            setTemplates(normalizedTemplates);
            setSignatures(normalizedSignatures);

            if (normalizedSignatures.length > 0 && !selectedSignatureId) {
                handleSelectSignature(normalizedSignatures[0]);
            }
        } catch (error) {
            console.error('Error loading design data:', error);
        }
    };

    const handleSaveTemplate = async () => {
        if (!editingTemplate) return;
        setIsSavingTemplate(true);
        const payload = {
            ...editingTemplate,
            automationType: editingTemplate.slug,
        };
        try {
            await api.put(`/marketing/email-templates/${editingTemplate.id}`, payload);
            setTemplates(prev => prev.map(t => t.id === editingTemplate.id ? { ...editingTemplate, ...payload } as EmailTemplate : t));
            setEditingTemplate(null);
            alert('Template salvo com sucesso!');
        } catch (error: any) {
            console.error('Error saving template:', error.response?.data || error);
            alert(`Erro ao salvar template: ${error.response?.data?.message || 'Erro desconhecido'}`);
        } finally {
            setIsSavingTemplate(false);
        }
    };

    const handleCreateTemplate = async (e: React.FormEvent) => {
        e.preventDefault();

        if (!newTemplate.slug) {
            alert('Por favor, selecione um Tipo de Automação');
            return;
        }

        setIsSavingTemplate(true);
        const payload = {
            ...newTemplate,
            automationType: newTemplate.slug,
            signatureId: newTemplate.signatureId || null
        };
        try {
            const res = await api.post('/marketing/email-templates', payload);
            setTemplates(prev => [...prev, res.data]);
            setIsCreatingTemplate(false);
            setNewTemplate({ name: '', slug: '', subject: '', content: '', signatureId: null, active: true });
            alert('Template criado com sucesso!');
        } catch (error: any) {
            console.error('Error creating template:', error.response?.data || error);
            alert(`Erro ao criar template: ${error.response?.data?.message || 'Erro do servidor'}`);
        } finally {
            setIsSavingTemplate(false);
        }
    };

    const handleDeleteTemplate = async (id: string) => {
        if (!confirm('Excluir este template permanentemente?')) return;
        try {
            await api.delete(`/marketing/email-templates/${id}`);
            setTemplates(prev => prev.filter(t => t.id !== id));
            if (editingTemplate?.id === id) setEditingTemplate(null);
        } catch (error) {
            console.error('Error deleting template:', error);
        }
    };

    // --- Logic: Campaigns ---
    const loadCampaigns = async () => {
        try {
            const res = await api.get('/marketing/campaigns');
            // Normalizar campanhas para garantir que estados controlados não recebam null
            const normalizedCampaigns = res.data.map((c: any) => ({
                ...c,
                name: c.name || '',
                subject: c.subject || '',
                content: c.content || '',
                audience: c.audience || ''
            }));
            setCampaigns(normalizedCampaigns);
        } catch (error) {
            console.error('Error loading campaigns:', error);
        }
    };

    const handleCreateCampaign = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsSavingCampaign(true);
        try {
            if (newCampaign.id) {
                await api.put(`/marketing/campaigns/${newCampaign.id}`, newCampaign);
            } else {
                await api.post('/marketing/campaigns', newCampaign);
            }
            loadCampaigns();
            setIsCreatingCampaign(false);
            setNewCampaign({ name: '', subject: '', content: '', status: 'PENDING', totalRecipients: 0, sentCount: 0, audience: 'NEWSLETTER_SUBSCRIBERS', signatureId: null });
            alert(newCampaign.id ? 'Campanha atualizada!' : 'Campanha criada com sucesso!');
        } catch (error: any) {
            console.error('Error saving campaign:', error.response?.data || error);
            alert(`Erro ao salvar campanha: ${error.response?.data?.message || 'Erro interno'}`);
        } finally {
            setIsSavingCampaign(false);
        }
    };

    const handleEditCampaign = (campaign: EmailCampaign) => {
        if (campaign.status !== 'PENDING') {
            alert('Apenas campanhas em rascunho (PENDING) podem ser editadas.');
            return;
        }
        setNewCampaign(campaign);
        setIsCreatingCampaign(true);
    };

    const handleCancelCampaign = async (id: string) => {
        if (!confirm('Deseja interromper o envio desta campanha?')) return;
        try {
            await api.post(`/marketing/campaigns/${id}/cancel`);
            loadCampaigns();
            alert('Envio interrompido.');
        } catch (error) {
            console.error('Error cancelling campaign:', error);
            alert('Erro ao cancelar campanha.');
        }
    };

    const handleStartCampaign = async (id: string) => {
        if (!confirm('Deseja enviar esta campanha agora? Essa ação disparará os emails imediatamente para todos os contatos do público alvo selecionado.')) return;
        try {
            await api.post(`/marketing/campaigns/${id}/start`);
            loadCampaigns();
            alert('Campanha iniciada com sucesso! Você pode acompanhar o progresso na aba "Monitoramento".');
        } catch (error) {
            console.error('Error starting campaign:', error);
            alert('Erro ao iniciar a campanha.');
        }
    };

    const handleDeleteCampaign = async (id: string) => {
        if (!confirm('Excluir esta campanha? Histórico de envios será mantido nos relatórios, porém o registro da campanha será apagado.')) return;
        try {
            await api.delete(`/marketing/campaigns/${id}`);
            loadCampaigns();
        } catch (error) {
            console.error('Error deleting campaign:', error);
        }
    };

    // --- Logic: Design (Signatures) ---
    const handleSelectSignature = (sig: Signature) => {
        setSelectedSignatureId(sig.id || null);
        setSignatureForm(sig);
    };

    const handleNewSignature = () => {
        setSelectedSignatureId(null);
        setSignatureForm({
            name: 'Nova Assinatura',
            ownerName: '',
            role: 'Direção',
            storeName: 'Ateliê Filhos de Aruanda',
            whatsapp: '',
            email: '',
            storeUrl: 'https://www.atelie.com.br',
            logoUrl: 'https://via.placeholder.com/150',
            motto: ''
        });
    }

    const handleSaveSignature = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsSavingSignature(true);
        console.log('DEBUG: Saving signature payload:', JSON.stringify(signatureForm));
        try {
            await api.post('/marketing/signatures', signatureForm);
            loadDesignData();
            alert('Assinatura salva!');
        } catch (error: any) {
            console.error('Error saving signature:', error.response?.data || error);
            alert(`Erro ao salvar assinatura: ${error.response?.data?.message || 'Erro desconhecido'}`);
        } finally {
            setIsSavingSignature(false);
        }
    };

    const handleDeleteSignature = async (id: string) => {
        if (!confirm('Deseja excluir esta assinatura?')) return;
        try {
            await api.delete(`/marketing/signatures/${id}`);
            loadDesignData();
            handleNewSignature();
        } catch (error) {
            console.error('Error deleting signature:', error);
        }
    };

    const handleLogoUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files[0]) {
            setIsUploading(true);
            setUploadProgress(0);
            try {
                const response = await MediaService.upload(e.target.files[0], (p) => setUploadProgress(p));
                setSignatureForm(prev => ({ ...prev, logoUrl: response.url }));
            } catch (err) {
                console.error("Upload failed", err);
            } finally {
                setIsUploading(false);
                setUploadProgress(0);
            }
        }
    };


    const renderSignaturePreviewById = (signatureId: string | null) => {
        const sig = signatures.find(s => s.id === signatureId);
        if (!sig) return (
            <div className="p-4 bg-gray-50 border-2 border-dashed rounded-xl text-center text-gray-400 text-xs italic">
                Nenhuma assinatura selecionada para este template.
            </div>
        );

        const storeUrlLabel = sig.storeUrl?.replace(/https?:\/\//, '').replace('www.', '') || '';

        return (
            <div className="bg-white border p-4 rounded-xl shadow-inner scale-90 origin-top">
                <table cellPadding="0" cellSpacing="0" border={0} style={{ fontFamily: 'Arial, sans-serif', color: '#1B2B42', width: '100%', maxWidth: '500px' }}>
                    <tbody>
                        <tr>
                            <td width="100" style={{ paddingRight: '15px', borderRight: '2px solid #D4AF37' }}>
                                <img src={getImageUrl(sig.logoUrl)} alt="Logo" width="80" style={{ display: 'block', borderRadius: '50%', border: '1px solid #EBEBEB' }} />
                            </td>
                            <td style={{ paddingLeft: '15px' }}>
                                <h2 style={{ margin: '0 0 2px 0', color: '#1B2B42', fontSize: '16px', fontWeight: 'bold' }}>{sig.ownerName}</h2>
                                <p style={{ margin: '0 0 8px 0', color: '#555555', fontSize: '12px' }}>
                                    {sig.role} | <strong style={{ color: '#1B2B42' }}>{sig.storeName}</strong>
                                </p>
                                <p style={{ margin: '0', fontSize: '11px', lineHeight: '1.4', color: '#333333' }}>
                                    <strong>WhatsApp:</strong> {sig.whatsapp}<br />
                                    <strong>E-mail:</strong> {sig.email}<br />
                                    <strong>Loja:</strong> <span style={{ color: '#D4AF37', fontWeight: 'bold' }}>{storeUrlLabel}</span>
                                </p>
                            </td>
                        </tr>
                    </tbody>
                </table>
            </div>
        );
    };

    const renderSignaturePreview = () => {
        const storeUrlLabel = signatureForm.storeUrl?.replace(/https?:\/\//, '').replace('www.', '') || '';
        return (
            <div className="bg-white border p-8 rounded-xl shadow-inner min-h-[200px] flex items-center justify-center">
                <table cellPadding="0" cellSpacing="0" border={0} style={{ fontFamily: 'Arial, sans-serif', color: '#1B2B42', width: '100%', maxWidth: '500px' }}>
                    <tbody>
                        <tr>
                            <td width="130" style={{ paddingRight: '20px', borderRight: '2px solid #D4AF37' }}>
                                <img src={getImageUrl(signatureForm.logoUrl)} alt="Logo" width="110" style={{ display: 'block', borderRadius: '50%', border: '1px solid #EBEBEB' }} />
                            </td>
                            <td style={{ paddingLeft: '20px' }}>
                                <h2 style={{ margin: '0 0 4px 0', color: '#1B2B42', fontSize: '20px', fontWeight: 'bold' }}>{signatureForm.ownerName || '[Seu Nome]'}</h2>
                                <p style={{ margin: '0 0 12px 0', color: '#555555', fontSize: '14px' }}>
                                    {signatureForm.role} | <strong style={{ color: '#1B2B42' }}>{signatureForm.storeName}</strong>
                                </p>
                                <p style={{ margin: '0', fontSize: '13px', lineHeight: '1.6', color: '#333333' }}>
                                    <span style={{ color: '#D4AF37' }}>✦</span> <strong>WhatsApp:</strong> {signatureForm.whatsapp || '(00) 00000-0000'}<br />
                                    <span style={{ color: '#D4AF37' }}>✦</span> <strong>E-mail:</strong> <span style={{ color: '#1B2B42' }}>{signatureForm.email || 'contato@empresa.com'}</span><br />
                                    <span style={{ color: '#D4AF37' }}>✦</span> <strong>Loja:</strong> <span style={{ color: '#D4AF37', fontWeight: 'bold' }}>{storeUrlLabel || 'www.loja.com.br'}</span>
                                </p>
                            </td>
                        </tr>
                        <tr>
                            <td colSpan={2} style={{ paddingTop: '15px' }}>
                                <p style={{ margin: '0', fontSize: '12px', color: '#777777', fontStyle: 'italic', borderTop: '1px solid #EEEEEE', paddingTop: '8px' }}>
                                    {signatureForm.motto || 'Sua frase de efeito aqui.'}
                                </p>
                            </td>
                        </tr>
                    </tbody>
                </table>
            </div>
        );
    };

    // --- Logic: Config (SMTP) ---
    const loadSMTPConfigs = async () => {
        try {
            const res = await api.get('/marketing/email-settings');
            if (res.data) {
                // Normalizar SMTP configs para evitar warnings de "controlled to uncontrolled" no React
                const normalized = {
                    ...res.data,
                    mailHost: res.data.mailHost || '',
                    mailUsername: res.data.mailUsername || '',
                    mailPassword: res.data.mailPassword || '',
                    mailSenderAddress: res.data.mailSenderAddress || '',
                    mailSenderName: res.data.mailSenderName || ''
                };
                setSmtpConfig(normalized);
            }
        } catch (error) {
            console.error('Error loading SMTP configs:', error);
        }
    };

    const handleApplyProvider = (p: typeof SMTP_PROVIDERS[0]) => {
        if (p.name === 'Custom') {
            setSmtpConfig(prev => ({ ...prev, mailHost: '', mailPort: 587 }));
        } else {
            setSmtpConfig(prev => ({ ...prev, mailHost: p.host, mailPort: p.port }));
        }
    };

    const handleSaveSMTP = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsSavingSMTP(true);
        try {
            await api.post('/marketing/email-settings', smtpConfig);
            alert('Configurações SMTP salvas!');
        } catch (error) {
            console.error('Error saving SMTP settings:', error);
            alert('Erro ao salvar SMTP.');
        } finally {
            setIsSavingSMTP(false);
        }
    };

    // --- Helper UI ---
    const getStatusIcon = (status: string) => {
        switch (status) {
            case 'SENT': return <CheckCircle className="w-4 h-4 text-green-500" />;
            case 'FAILED': return <AlertCircle className="w-4 h-4 text-red-500" />;
            case 'PENDING': return <Clock className="w-4 h-4 text-amber-500" />;
            default: return <Mail className="w-4 h-4 text-gray-400" />;
        }
    };

    const filteredQueue = queue.filter(e => queueFilter === 'ALL' || e.status === queueFilter);

    // --- RENDERS ---

    const renderAnalytics = () => (
        <div className="space-y-6 animate-in fade-in duration-300">
            <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
                {[
                    { label: 'Total Enviado', value: metrics.totalSent, icon: Send, color: 'indigo' },
                    { label: 'Assinantes Newsletter', value: metrics.totalNewsletter, icon: User, color: 'blue' },
                    { label: 'Em Pendência', value: metrics.pending, icon: Clock, color: 'amber' },
                    { label: 'Falhas de Envio', value: metrics.failed, icon: AlertCircle, color: 'red' },
                    { label: 'Usuários Verificados', value: metrics.verifiedUsers, icon: CheckCircle, color: 'green' },
                ].map(card => (
                    <div key={card.label} className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex items-center gap-4">
                        <div className={`p-3 bg-${card.color}-100 rounded-xl text-${card.color}-600`}>
                            <card.icon size={24} />
                        </div>
                        <div>
                            <p className="text-sm text-gray-500 font-medium">{card.label}</p>
                            <h3 className="text-2xl font-bold text-gray-800">{card.value}</h3>
                        </div>
                    </div>
                ))}
            </div>

            <div className="bg-white rounded-2xl shadow-sm border overflow-hidden">
                <div className="px-6 py-4 border-b bg-gray-50 flex justify-between items-center">
                    <h2 className="font-bold text-gray-800 flex items-center gap-2">
                        <RefreshCcw size={18} className={loadingAnalytics ? "animate-spin text-indigo-500" : ""} />
                        Fila de Processamento
                    </h2>
                    <div className="flex gap-2 items-center">
                        {metrics.failed > 0 && (
                            <button
                                onClick={handleRetryAllFailed}
                                className="mr-4 px-3 py-1 bg-red-50 text-red-600 text-xs font-black rounded-lg border border-red-100 hover:bg-red-100 transition flex items-center gap-2"
                            >
                                <RefreshCcw size={12} /> REENVIAR TODAS AS FALHAS
                            </button>
                        )}
                        {['ALL', 'PENDING', 'SENT', 'FAILED'].map(f => (
                            <button
                                key={f}
                                onClick={() => setQueueFilter(f)}
                                className={clsx(
                                    "px-3 py-1 text-xs font-bold rounded-full transition",
                                    queueFilter === f ? "bg-indigo-600 text-white shadow-md shadow-indigo-100" : "bg-gray-100 text-gray-600 hover:bg-gray-200"
                                )}
                            >
                                {f === 'ALL' ? 'Tudo' : f === 'PENDING' ? 'Pendentes' : f === 'SENT' ? 'Enviados' : 'Falhas'}
                            </button>
                        ))}
                    </div>
                </div>
                <div className="overflow-x-auto max-h-[500px] overflow-y-auto">
                    <table className="w-full text-left">
                        <thead className="bg-gray-50 text-xs text-gray-500 uppercase font-bold sticky top-0">
                            <tr>
                                <th className="px-6 py-3">Destinatário</th>
                                <th className="px-6 py-3">Assunto</th>
                                <th className="px-6 py-3">Status</th>
                                <th className="px-6 py-3 text-right">Ação</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y text-sm">
                            {filteredQueue.length === 0 ? (
                                <tr><td colSpan={4} className="px-6 py-12 text-center text-gray-400 italic">Nenhum e-mail na fila.</td></tr>
                            ) : filteredQueue.map(email => (
                                <tr key={email.id} className="hover:bg-gray-50 group">
                                    <td className="px-6 py-4 font-semibold text-gray-700">{email.recipient}</td>
                                    <td className="px-6 py-4 text-gray-500 max-w-[200px] truncate">{email.subject}</td>
                                    <td className="px-6 py-4">
                                        <div className="flex items-center gap-2">
                                            {getStatusIcon(email.status)}
                                            <span className={clsx(
                                                "text-xs font-bold",
                                                email.status === 'SENT' && "text-green-600",
                                                email.status === 'FAILED' && "text-red-600",
                                                email.status === 'PENDING' && "text-amber-600"
                                            )}>{email.status}</span>
                                        </div>
                                    </td>
                                    <td className="px-6 py-4 text-right">
                                        {email.status === 'FAILED' && (
                                            <button
