                                <span className="text-sm font-bold text-gray-600">Visualização em Tempo Real</span>
                            </div>
                            <div className="p-6 bg-gray-100">
                                {renderSignaturePreview()}
                            </div>
                        </div>

                        <form onSubmit={handleSaveSignature} className="bg-white rounded-2xl border shadow-sm p-6 space-y-6">
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                <div className="space-y-4">
                                    <h4 className="font-bold text-gray-800 border-b pb-2">Informações Pessoais</h4>
                                    <div className="space-y-3">
                                        <div>
                                            <label className="block text-[10px] font-bold text-gray-500 uppercase mb-1">Nome Interno</label>
                                            <input type="text" required value={signatureForm.name || ''} onChange={e => setSignatureForm({ ...signatureForm, name: e.target.value })} className="w-full px-4 py-2 border rounded-lg text-sm" />
                                        </div>
                                        <div>
                                            <label className="block text-[10px] font-bold text-gray-500 uppercase mb-1">Seu Nome (Exibido)</label>
                                            <input type="text" required value={signatureForm.ownerName || ''} onChange={e => setSignatureForm({ ...signatureForm, ownerName: e.target.value })} className="w-full px-4 py-2 border rounded-lg text-sm" />
                                        </div>
                                        <div>
                                            <label className="block text-[10px] font-bold text-gray-500 uppercase mb-1">Cargo / Função</label>
                                            <input type="text" required value={signatureForm.role || ''} onChange={e => setSignatureForm({ ...signatureForm, role: e.target.value })} className="w-full px-4 py-2 border rounded-lg text-sm" />
                                        </div>
                                    </div>
                                </div>
                                <div className="space-y-4">
                                    <h4 className="font-bold text-gray-800 border-b pb-2">Contato e Branding</h4>
                                    <div className="space-y-3">
                                        <div className="space-y-2">
                                            <label className="block text-[10px] font-bold text-gray-500 uppercase">Logo da Assinatura</label>
                                            <div className="flex items-center gap-4 p-3 border rounded-xl bg-gray-50">
                                                <div className="w-12 h-12 rounded-full border bg-white overflow-hidden relative">
                                                    <img src={getImageUrl(signatureForm.logoUrl)} className="w-full h-full object-cover" />
                                                    {isUploading && <div className="absolute inset-0 bg-white/80 flex items-center justify-center"><RefreshCcw size={14} className="animate-spin text-indigo-600" /></div>}
                                                </div>
                                                <label className="cursor-pointer px-3 py-1.5 bg-white border rounded-lg text-xs font-bold hover:bg-gray-100 transition shadow-sm flex items-center gap-2">
                                                    <Upload size={14} /> {isUploading ? `${uploadProgress}%` : 'Alterar'}
                                                    <input type="file" className="hidden" accept="image/*" onChange={handleLogoUpload} disabled={isUploading} />
                                                </label>
                                            </div>
                                        </div>
                                        <div>
                                            <label className="block text-[10px] font-bold text-gray-500 uppercase mb-1">WhatsApp</label>
                                            <input
                                                type="text" required
                                                value={signatureForm.whatsapp || ''}
                                                onChange={e => setSignatureForm({ ...signatureForm, whatsapp: formatPhone(e.target.value) })}
                                                className="w-full px-4 py-2 border rounded-lg text-sm"
                                                placeholder="(00) 00000-0000"
                                            />
                                        </div>
                                        <div>
                                            <label className="block text-[10px] font-bold text-gray-500 uppercase mb-1">E-mail de Contato</label>
                                            <input type="email" required value={signatureForm.email || ''} onChange={e => setSignatureForm({ ...signatureForm, email: e.target.value })} className="w-full px-4 py-2 border rounded-lg text-sm" />
                                        </div>
                                    </div>
                                </div>
                            </div>
                            <div className="space-y-4">
                                <h4 className="font-bold text-gray-800 border-b pb-2">Detalhes da Loja</h4>
                                <div className="grid grid-cols-2 gap-4">
                                    <div>
                                        <label className="block text-[10px] font-bold text-gray-500 uppercase mb-1">Nome da Loja</label>
                                        <input type="text" required value={signatureForm.storeName || ''} onChange={e => setSignatureForm({ ...signatureForm, storeName: e.target.value })} className="w-full px-4 py-2 border rounded-lg text-sm" />
                                    </div>
                                    <div>
                                        <label className="block text-[10px] font-bold text-gray-500 uppercase mb-1">URL da Loja</label>
                                        <input type="url" required value={signatureForm.storeUrl || ''} onChange={e => setSignatureForm({ ...signatureForm, storeUrl: e.target.value })} className="w-full px-4 py-2 border rounded-lg text-sm" />
                                    </div>
                                </div>
                                <input type="text" required placeholder="Lema / Frase de efeito" value={signatureForm.motto || ''} onChange={e => setSignatureForm({ ...signatureForm, motto: e.target.value })} className="w-full px-4 py-2 border rounded-lg text-sm" />
                            </div>
                            <div className="flex justify-end pt-4 border-t">
                                <button type="submit" disabled={isSavingSignature} className="px-8 py-2 bg-indigo-600 text-white font-bold rounded-lg shadow-lg hover:bg-indigo-700 transition flex items-center gap-2">
                                    <Save size={18} /> {isSavingSignature ? 'Salvando...' : 'Salvar Assinatura'}
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );

    const renderConfig = () => (
        <div className="max-w-4xl mx-auto animate-in fade-in duration-300">
            <div className="bg-white rounded-3xl shadow-xl border border-gray-100 overflow-hidden">
                <div className="p-8 bg-indigo-600 text-white text-center">
                    <div className="flex flex-col items-center mb-6">
                        <div className="p-4 bg-white/20 rounded-full mb-4">
                            <Server size={40} />
                        </div>
                        <h1 className="text-2xl font-bold">Servidor SMTP</h1>
                        <p className="text-white/70 text-sm max-w-sm">Configure o motor para envios automáticos e campanhas.</p>
                    </div>

                    <div className="flex flex-wrap justify-center gap-3">
                        {SMTP_PROVIDERS.map(p => (
                            <button
                                key={p.name}
                                type="button"
                                onClick={() => handleApplyProvider(p)}
                                className={clsx(
                                    "px-5 py-2.5 rounded-xl text-sm font-bold transition-all border",
                                    smtpConfig.mailHost === p.host && p.host !== '' ? "bg-white text-indigo-600 border-white shadow-lg" : "bg-white/10 text-white border-white/20 hover:bg-white/20"
                                )}
                            >
                                {p.name}
                            </button>
                        ))}
                    </div>
                </div>

                <form onSubmit={handleSaveSMTP} className="p-8 space-y-8">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                        <div className="space-y-6">
                            <h3 className="font-bold text-gray-400 text-[10px] uppercase tracking-widest border-b pb-2">Identidade</h3>
                            <div className="space-y-4">
                                <div>
                                    <label className="block text-xs font-bold text-gray-600 uppercase mb-2">Nome Exibido</label>
                                    <div className="relative">
                                        <User className="absolute left-3 top-2.5 text-gray-300" size={18} />
                                        <input className="w-full pl-10 pr-4 py-2 border rounded-xl" placeholder="Ateliê Filhos de Aruanda" value={smtpConfig.mailSenderName} onChange={e => setSmtpConfig({ ...smtpConfig, mailSenderName: e.target.value })} />
                                    </div>
                                </div>
                                <div>
                                    <label className="block text-xs font-bold text-gray-600 uppercase mb-2">E-mail Remetente</label>
                                    <div className="relative">
                                        <Mail className="absolute left-3 top-2.5 text-gray-300" size={18} />
                                        <input type="email" className="w-full pl-10 pr-4 py-2 border rounded-xl" placeholder="contato@atelie.com.br" value={smtpConfig.mailSenderAddress} onChange={e => setSmtpConfig({ ...smtpConfig, mailSenderAddress: e.target.value })} />
                                    </div>
                                </div>
                            </div>
                        </div>

                        <div className="space-y-6">
                            <h3 className="font-bold text-gray-400 text-[10px] uppercase tracking-widest border-b pb-2">Servidor</h3>
                            <div className="grid grid-cols-3 gap-3">
                                <div className="col-span-2">
                                    <label className="block text-xs font-bold text-gray-600 uppercase mb-2">Host</label>
                                    <input className="w-full px-3 py-2 border rounded-xl" placeholder="smtp.servidor.com" value={smtpConfig.mailHost} onChange={e => setSmtpConfig({ ...smtpConfig, mailHost: e.target.value })} />
                                </div>
                                <div>
                                    <label className="block text-xs font-bold text-gray-600 uppercase mb-2">Porta</label>
                                    <input type="number" className="w-full px-3 py-2 border rounded-xl text-center" value={smtpConfig.mailPort} onChange={e => setSmtpConfig({ ...smtpConfig, mailPort: parseInt(e.target.value) })} />
                                </div>
                            </div>
                            <div>
                                <label className="block text-xs font-bold text-gray-600 uppercase mb-2">Usuário / API Key</label>
                                <input className="w-full px-3 py-2 border rounded-xl" value={smtpConfig.mailUsername} onChange={e => setSmtpConfig({ ...smtpConfig, mailUsername: e.target.value })} />
                            </div>
                            <div>
                                <label className="block text-xs font-bold text-gray-600 uppercase mb-2">Senha / Token</label>
                                <div className="relative">
                                    <input type={showPassword ? "text" : "password"} className="w-full px-3 py-2 border rounded-xl" value={smtpConfig.mailPassword} onChange={e => setSmtpConfig({ ...smtpConfig, mailPassword: e.target.value })} />
                                    <button type="button" onClick={() => setShowPassword(!showPassword)} className="absolute right-3 top-2.5 text-[9px] font-black text-indigo-500 uppercase">{showPassword ? "Ocultar" : "Mostrar"}</button>
                                </div>
                            </div>
                        </div>
                    </div>

                    <div className="pt-8 border-t flex justify-end">
                        <button type="submit" disabled={isSavingSMTP} className="px-12 py-4 bg-indigo-600 text-white font-black rounded-2xl shadow-xl hover:bg-indigo-700 transition active:scale-95 disabled:bg-indigo-300">
                            {isSavingSMTP ? 'SALVANDO...' : 'SALVAR E ATATIVAR'}
                        </button>
                    </div>
                </form>
            </div>
        </div>
    );

    return (
        <div className="space-y-8 pb-20">
            <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
                <div>
                    <h1 className="text-3xl font-black text-gray-900 tracking-tight">E-mail Marketing</h1>
                    <p className="text-gray-500 font-medium mt-1">Sua central unificada de automação e comunicações.</p>
                </div>

                <div className="flex p-1.5 bg-white rounded-2xl shadow-sm border border-gray-100">
                    {[
                        { id: 'analytics', label: 'Monitoramento', icon: LayoutDashboard },
                        { id: 'design', label: 'Criação', icon: PenTool },
                        { id: 'config', label: 'Infraestrutura', icon: Settings },
                    ].map(tab => (
                        <button
                            key={tab.id}
                            onClick={() => setActiveTab(tab.id as any)}
                            className={clsx(
                                "flex items-center gap-2 px-5 py-2.5 rounded-xl text-sm font-bold transition-all",
                                activeTab === tab.id ? "bg-indigo-600 text-white shadow-lg" : "text-gray-500 hover:bg-gray-50"
                            )}
                        >
                            <tab.icon size={18} />
                            {tab.label}
                        </button>
                    ))}
                </div>
            </div>

            <div className="min-h-[500px]">
                {activeTab === 'analytics' && renderAnalytics()}
                {activeTab === 'design' && renderDesign()}
                {activeTab === 'config' && renderConfig()}
            </div>

        </div>
    );
}

import { useState, useEffect } from 'react';
import { Mail, Save, PenTool, Edit2, Plus, Trash2 } from 'lucide-react';

import { api } from '../../api/axios';
import { RichTextEditor } from '../../components/common/RichTextEditor';
import BaseModal from '../../components/ui/BaseModal';
import Button from '../../components/ui/Button';
import { useToast } from '../../context/ToastContext';
import clsx from 'clsx';

interface EmailTemplate {
    id: string;
    slug: string;
    name: string;
    subject: string;
    content: string;
    signatureId: string | null;
    active: boolean;
}

export default function EmailTemplatesPage() {
    const [templates, setTemplates] = useState<EmailTemplate[]>([]);
    const [signatures, setSignatures] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const [editingTemplate, setEditingTemplate] = useState<EmailTemplate | null>(null);
    const [isSaving, setIsSaving] = useState(false);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const { addToast } = useToast();
    const [newTemplate, setNewTemplate] = useState({
        name: '',
        slug: '',
        subject: '',
        content: '',
        signatureId: '',
        active: true
    });

    useEffect(() => {
        loadData();
    }, []);

    const loadData = async () => {
        try {
            const [templatesRes, signaturesRes] = await Promise.all([
                api.get('/marketing/email-templates'),
                api.get('/marketing/signatures')
            ]);
            setTemplates(templatesRes.data);
            setSignatures(signaturesRes.data);
        } catch (error) {
            console.error('Error loading data:', error);
        } finally {
            setLoading(false);
        }
    };

    const handleEdit = (template: EmailTemplate) => {
        setEditingTemplate({ ...template });
    };

    const handleSave = async () => {
        if (!editingTemplate) return;
        setIsSaving(true);
        try {
            await api.put(`/marketing/email-templates/${editingTemplate.id}`, editingTemplate);
            setTemplates(prev => prev.map(t => t.id === editingTemplate.id ? editingTemplate : t));
            setEditingTemplate(null);
            addToast('Template atualizado com sucesso!', 'success');
        } catch (error) {
            console.error('Error saving template:', error);
            addToast('Erro ao salvar template.', 'error');
        } finally {
            setIsSaving(false);
        }
    };

    const handleCreate = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsSaving(true);
        try {
            const res = await api.post('/marketing/email-templates', {
                ...newTemplate,
                signatureId: newTemplate.signatureId || null
            });
            setTemplates(prev => [...prev, res.data]);
            setIsModalOpen(false);
            setNewTemplate({
                name: '',
                slug: '',
                subject: '',
                content: '',
                signatureId: '',
                active: true
            });
            addToast('Template criado com sucesso!', 'success');
        } catch (error) {
            console.error('Error creating template:', error);
            addToast('Erro ao criar template. Verifique se o slug é único.', 'error');
        } finally {
            setIsSaving(false);
        }
    };

    const handleDelete = async (id: string, e: React.MouseEvent) => {
        e.stopPropagation();
        if (!confirm('Tem certeza que deseja excluir este template?')) return;
        try {
            await api.delete(`/marketing/email-templates/${id}`);
            setTemplates(prev => prev.filter(t => t.id !== id));
            if (editingTemplate?.id === id) setEditingTemplate(null);
            addToast('Template excluído.', 'success');
        } catch (error) {
            console.error('Error deleting template:', error);
            addToast('Erro ao excluir template.', 'error');
        }
    };

    return (
        <div className="space-y-6 pb-20">
            <div className="flex justify-between items-center">
                <div>
                    <h1 className="text-2xl font-bold text-gray-900">Mensagens Automáticas</h1>
                    <p className="text-gray-500">Personalize os e-mails enviados automaticamente pelo sistema.</p>
                </div>
                <Button
                    onClick={() => setIsModalOpen(true)}
                    variant="primary"
                    className="shadow-lg"
                >
                    <Plus size={20} />
                    Nova Mensagem
                </Button>
            </div>

            {/* Modal de Criação */}
            <BaseModal
                isOpen={isModalOpen}
                onClose={() => setIsModalOpen(false)}
                title="Novo Template"
                maxWidth="max-w-2xl"
            >
                <form onSubmit={handleCreate} className="space-y-4">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div>
                            <label className="block text-sm font-semibold text-gray-700 mb-1">Nome</label>
                            <input
                                type="text"
                                required
                                placeholder="Ex: Boas-vindas"
                                className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                                value={newTemplate.name}
                                onChange={e => setNewTemplate({ ...newTemplate, name: e.target.value })}
                            />
                        </div>
                        <div>
                            <label className="block text-sm font-semibold text-gray-700 mb-1">Identificador (Slug)</label>
                            <input
                                type="text"
                                required
                                placeholder="Ex: WELCOME_EMAIL"
                                className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none uppercase"
                                value={newTemplate.slug}
                                onChange={e => setNewTemplate({ ...newTemplate, slug: e.target.value.toUpperCase() })}
                            />
                        </div>
                    </div>

                    <div>
                        <label className="block text-sm font-semibold text-gray-700 mb-1">Assunto do E-mail</label>
                        <input
                            type="text"
                            required
                            placeholder="Assunto que o cliente verá"
                            className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                            value={newTemplate.subject}
                            onChange={e => setNewTemplate({ ...newTemplate, subject: e.target.value })}
                        />
                    </div>

                    <div>
                        <label className="block text-sm font-semibold text-gray-700 mb-1">Assinatura</label>
                        <select
                            className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                            value={newTemplate.signatureId}
                            onChange={e => setNewTemplate({ ...newTemplate, signatureId: e.target.value })}
                        >
                            <option value="">Sem assinatura</option>
                            {signatures.map(sig => (
                                <option key={sig.id} value={sig.id}>{sig.name}</option>
                            ))}
                        </select>
                    </div>

                    <div>
                        <label className="block text-sm font-semibold text-gray-700 mb-1">Conteúdo</label>
                        <RichTextEditor
                            value={newTemplate.content}
                            onChange={content => setNewTemplate({ ...newTemplate, content })}
                        />
                    </div>

                    <div className="pt-4 border-t flex justify-end gap-3">
                        <Button
                            type="button"
                            onClick={() => setIsModalOpen(false)}
                            variant="secondary"
                        >
                            Cancelar
                        </Button>
                        <Button
                            type="submit"
                            isLoading={isSaving}
                            variant="primary"
                            className="px-6 shadow-lg"
                        >
                            Criar Template
                        </Button>
                    </div>
                </form>
            </BaseModal>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                {/* Lista de Templates */}
                <div className="space-y-4">
                    {loading ? (
                        <div className="p-10 text-center text-gray-400">Carregando...</div>
                    ) : templates.map(t => (
                        <div
                            key={t.id}
                            onClick={() => handleEdit(t)}
                            className={clsx(
                                "p-4 rounded-xl border-2 cursor-pointer transition group relative",
                                editingTemplate?.id === t.id
                                    ? "border-indigo-600 bg-indigo-50"
                                    : "border-transparent bg-white hover:border-gray-200 shadow-sm"
                            )}
                        >
                            <div className="flex items-center gap-3">
                                <div className={clsx(
                                    "p-2 rounded-lg",
                                    t.active ? "bg-green-100 text-green-600" : "bg-gray-100 text-gray-400"
                                )}>
                                    <Mail className="w-5 h-5" />
                                </div>
                                <div className="flex-1">
                                    <h3 className="font-semibold text-gray-900">{t.name}</h3>
                                    <p className="text-xs text-gray-500 uppercase tracking-wider">{t.slug}</p>
                                </div>
                                <button
                                    onClick={(e) => handleDelete(t.id, e)}
                                    className="p-2 text-gray-400 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity"
                                >
                                    <Trash2 size={16} />
                                </button>
                            </div>
                        </div>
                    ))}
                </div>

                {/* Editor do Template Selecionado */}
                <div className="md:col-span-2">
                    {editingTemplate ? (
                        <div className="bg-white rounded-xl shadow-sm border p-6 space-y-6">
                            <div className="flex justify-between items-center border-b pb-4">
                                <div className="flex items-center gap-2">
                                    <Edit2 className="w-5 h-5 text-indigo-600" />
                                    <h2 className="text-lg font-bold text-gray-900">Editando: {editingTemplate.name}</h2>
                                </div>
                                <div className="flex items-center gap-3">
                                    <label className="flex items-center gap-2 cursor-pointer">
                                        <input
                                            type="checkbox"
                                            checked={editingTemplate.active}
                                            onChange={(e) => setEditingTemplate({ ...editingTemplate, active: e.target.checked })}
                                            className="w-4 h-4 rounded text-indigo-600"
                                        />
                                        <span className="text-sm font-medium text-gray-700">Ativo</span>
                                    </label>
                                    <Button
                                        onClick={handleSave}
                                        isLoading={isSaving}
                                        variant="primary"
                                        className="px-4 shadow-md"
                                    >
                                        <Save className="w-4 h-4 mr-2" />
                                        Salvar
                                    </Button>
                                </div>
                            </div>

                            <div className="space-y-4">
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1">Assunto do E-mail</label>
                                    <input
                                        type="text"
                                        value={editingTemplate.subject}
                                        onChange={(e) => setEditingTemplate({ ...editingTemplate, subject: e.target.value })}
                                        className="w-full px-4 py-2 rounded-lg border focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500"
                                    />
                                </div>

                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1">Assinatura</label>
                                    <div className="flex items-center gap-2">
                                        <PenTool className="w-5 h-5 text-gray-400" />
                                        <select
                                            value={editingTemplate.signatureId || ''}
                                            onChange={(e) => setEditingTemplate({ ...editingTemplate, signatureId: e.target.value || null })}
                                            className="w-full px-4 py-2 rounded-lg border focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500"
                                        >
                                            <option value="">Sem Assinatura</option>
                                            {signatures.map(sig => (
                                                <option key={sig.id} value={sig.id}>{sig.name}</option>
                                            ))}
                                        </select>
                                    </div>
                                </div>

                                <div>
                                    <div className="flex justify-between items-center mb-1">
                                        <label className="block text-sm font-medium text-gray-700">Conteúdo do E-mail</label>
                                        <span className="text-xs text-indigo-600 font-medium italic">Dica: use {"{{customer_name}}"} ou {"{{verification_link}}"} conforme template.</span>
                                    </div>
                                    <RichTextEditor
                                        value={editingTemplate.content}
                                        onChange={(val) => setEditingTemplate({ ...editingTemplate, content: val })}
                                    />
                                </div>
                            </div>
                        </div>
                    ) : (
                        <div className="bg-gray-50 border-2 border-dashed rounded-xl p-20 text-center">
                            <Mail className="w-12 h-12 text-gray-300 mx-auto mb-4" />
                            <h2 className="text-lg font-medium text-gray-900">Selecione um template</h2>
                            <p className="text-gray-500">Escolha uma mensagem automática na lista ao lado para editar ou crie uma nova.</p>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
}

import { useState, useEffect } from 'react';
import { PenTool, Save, Trash2, Eye, Plus, CheckCircle, Info, Upload, RefreshCcw } from 'lucide-react';
import { api } from '../../api/axios';
import { MediaService } from '../../services/MediaService';
import { getImageUrl } from '../../utils/imageUtils';

interface Signature {
    id?: string;
    name: string;
    ownerName: string;
    role: string;
    storeName: string;
    whatsapp: string;
    email: string;
    storeUrl: string;
    logoUrl: string;
    motto: string;
}

export function SignaturesPage() {
    const [signatures, setSignatures] = useState<Signature[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [isSaving, setIsSaving] = useState(false);
    const [isUploading, setIsUploading] = useState(false);
    const [uploadProgress, setUploadProgress] = useState(0);
    const [selectedId, setSelectedId] = useState<string | null>(null);

    const [formData, setFormData] = useState<Signature>({
        name: 'Assinatura Principal',
        ownerName: '',
        role: 'Direção',
        storeName: 'Ateliê Filhos de Aruanda',
        whatsapp: '',
        email: '',
        storeUrl: 'https://www.atelie.com.br',
        logoUrl: 'https://via.placeholder.com/150',
        motto: 'Arte e Espiritualidade guiando nossos caminhos.'
    });

    useEffect(() => {
        loadSignatures();
    }, []);

    const loadSignatures = async () => {
        try {
            const { data } = await api.get('/marketing/signatures');
            setSignatures(data);
            if (data.length > 0 && !selectedId) {
                handleSelect(data[0]);
            }
        } catch (error) {
            console.error('Erro ao carregar assinaturas', error);
        } finally {
            setIsLoading(false);
        }
    };

    const handleSelect = (sig: Signature) => {
        setSelectedId(sig.id || null);
        setFormData(sig);
    };

    const handleNew = () => {
        setSelectedId(null);
        setFormData({
            name: 'Nova Assinatura',
            ownerName: '',
            role: '',
            storeName: 'Ateliê Filhos de Aruanda',
            whatsapp: '',
            email: '',
            storeUrl: 'https://www.atelie.com.br',
            logoUrl: 'https://via.placeholder.com/150',
            motto: ''
        });
    };

    const handleSave = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsSaving(true);
        try {
            await api.post('/marketing/signatures', formData);
            alert('Assinatura salva com sucesso!');
            loadSignatures();
        } catch (error) {
            console.error('Erro ao salvar assinatura', error);
            alert('Erro ao salvar. Verifique os campos.');
        } finally {
            setIsSaving(false);
        }
    };

    const handleDelete = async (id: string) => {
        if (!confirm('Deseja realmente excluir esta assinatura?')) return;
        try {
            await api.delete(`/marketing/signatures/${id}`);
            loadSignatures();
            handleNew();
        } catch (error) {
            console.error('Erro ao excluir', error);
        }
    };

    const handleLogoUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files[0]) {
            const file = e.target.files[0];
            setIsUploading(true);
            setUploadProgress(0);
            try {
                const response = await MediaService.upload(file, (progress) => {
                    setUploadProgress(progress);
                });
                setFormData(prev => ({ ...prev, logoUrl: response.url }));
            } catch (err) {
                console.error("Upload failed", err);
                alert("Erro ao fazer upload do logo.");
            } finally {
                setIsUploading(false);
                setUploadProgress(0);
            }
        }
    };

    const renderPreview = () => {
        const storeUrlLabel = formData.storeUrl.replace(/https?:\/\//, '').replace('www.', '');
        return (
            <div className="bg-white border p-8 rounded-xl shadow-inner min-h-[200px] flex items-center justify-center">
                <table cellPadding="0" cellSpacing="0" border={0} style={{ fontFamily: 'Arial, sans-serif', color: '#1B2B42', width: '100%', maxWidth: '500px' }}>
                    <tbody>
                        <tr>
                            <td width="130" style={{ paddingRight: '20px', borderRight: '2px solid #D4AF37' }}>
                                <img src={getImageUrl(formData.logoUrl)} alt="Logo" width="110" style={{ display: 'block', borderRadius: '50%', border: '1px solid #EBEBEB' }} />
                            </td>
                            <td style={{ paddingLeft: '20px' }}>
                                <h2 style={{ margin: '0 0 4px 0', color: '#1B2B42', fontSize: '20px', fontWeight: 'bold' }}>{formData.ownerName || '[Seu Nome]'}</h2>
                                <p style={{ margin: '0 0 12px 0', color: '#555555', fontSize: '14px' }}>
                                    {formData.role} | <strong style={{ color: '#1B2B42' }}>{formData.storeName}</strong>
                                </p>
                                <p style={{ margin: '0', fontSize: '13px', lineHeight: '1.6', color: '#333333' }}>
                                    <span style={{ color: '#D4AF37' }}>✦</span> <strong>WhatsApp:</strong> {formData.whatsapp || '(00) 00000-0000'}<br />
                                    <span style={{ color: '#D4AF37' }}>✦</span> <strong>E-mail:</strong> <span style={{ color: '#1B2B42' }}>{formData.email || 'contato@empresa.com'}</span><br />
                                    <span style={{ color: '#D4AF37' }}>✦</span> <strong>Loja:</strong> <span style={{ color: '#D4AF37', fontWeight: 'bold' }}>{storeUrlLabel || 'www.loja.com.br'}</span>
                                </p>
                            </td>
                        </tr>
                        <tr>
                            <td colSpan={2} style={{ paddingTop: '15px' }}>
                                <p style={{ margin: '0', fontSize: '12px', color: '#777777', fontStyle: 'italic', borderTop: '1px solid #EEEEEE', paddingTop: '8px' }}>
                                    {formData.motto || 'Sua frase de efeito aqui.'}
                                </p>
                            </td>
                        </tr>
                    </tbody>
                </table>
            </div>
        );
    };

    return (
        <div className="space-y-6 max-w-6xl mx-auto">
            <div className="flex justify-between items-center">
                <div>
                    <h1 className="text-2xl font-bold text-gray-800 flex items-center gap-2">
                        <PenTool className="text-indigo-600" />
                        Assinaturas de E-mail
                    </h1>
                    <p className="text-sm text-gray-500 mt-1">Configure assinaturas elegantes para suas campanhas sem tocar em código.</p>
                </div>
                <button
                    onClick={handleNew}
                    className="px-4 py-2 bg-indigo-600 text-white rounded-lg font-bold shadow-lg hover:bg-indigo-700 transition flex items-center gap-2"
                >
                    <Plus size={20} /> Nova Assinatura
                </button>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                {/* Lista de Assinaturas */}
                <div className="lg:col-span-1 space-y-4">
                    <h3 className="text-sm font-bold text-gray-400 uppercase tracking-wider">Suas Assinaturas</h3>
                    {isLoading ? (
                        <div className="p-4 text-center text-gray-500">Carregando...</div>
                    ) : signatures.length === 0 ? (
                        <div className="bg-gray-50 border-2 border-dashed rounded-xl p-8 text-center">
                            <Info className="mx-auto text-gray-300 mb-2" size={32} />
                            <p className="text-gray-500 text-sm">Nenhuma assinatura criada.</p>
                        </div>
                    ) : (
                        <div className="space-y-2">
                            {signatures.map(sig => (
                                <button
                                    key={sig.id}
                                    onClick={() => handleSelect(sig)}
                                    className={`w-full text-left p-4 rounded-xl border transition-all flex justify-between items-center ${selectedId === sig.id ? 'border-indigo-600 bg-indigo-50 shadow-md ring-1 ring-indigo-600' : 'bg-white border-gray-200 hover:border-indigo-300'
                                        }`}
                                >
                                    <div>
                                        <p className={`font-bold text-sm ${selectedId === sig.id ? 'text-indigo-900' : 'text-gray-700'}`}>{sig.name}</p>
                                        <p className="text-xs text-gray-500">{sig.ownerName}</p>
                                    </div>
                                    {selectedId === sig.id && <CheckCircle size={18} className="text-indigo-600" />}
                                </button>
                            ))}
                        </div>
                    )}
                </div>

                {/* Editor e Preview */}
                <div className="lg:col-span-2 space-y-6">
                    <div className="bg-white rounded-2xl border shadow-sm overflow-hidden">
                        <div className="px-6 py-4 bg-gray-50 border-b flex items-center gap-2">
                            <Eye size={18} className="text-gray-400" />
                            <span className="text-sm font-bold text-gray-600">Visualização em Tempo Real</span>
                        </div>
                        <div className="p-6 bg-gray-100">
                            {renderPreview()}
                        </div>
                    </div>

                    <form onSubmit={handleSave} className="bg-white rounded-2xl border shadow-sm p-6 space-y-6">
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                            <div className="space-y-4">
                                <h4 className="font-bold text-gray-800 border-b pb-2 flex items-center gap-2">
                                    Informações Pessoais
                                </h4>
                                <div className="space-y-3">
                                    <div>
                                        <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Nome Interno</label>
                                        <input
                                            type="text" required value={formData.name}
                                            onChange={e => setFormData({ ...formData, name: e.target.value })}
                                            className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none text-sm"
                                        />
                                    </div>
                                    <div>
                                        <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Seu Nome (Exibido)</label>
                                        <input
                                            type="text" required value={formData.ownerName}
                                            onChange={e => setFormData({ ...formData, ownerName: e.target.value })}
                                            className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none text-sm"
                                        />
                                    </div>
                                    <div>
                                        <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Cargo / Função</label>
                                        <input
                                            type="text" required value={formData.role}
                                            onChange={e => setFormData({ ...formData, role: e.target.value })}
                                            className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none text-sm"
                                        />
                                    </div>
                                </div>
                            </div>

                            <div className="space-y-4">
                                <h4 className="font-bold text-gray-800 border-b pb-2 flex items-center gap-2">
                                    Contato e Branding
                                </h4>
                                <div className="space-y-3">
                                    <div className="space-y-2">
                                        <label className="block text-xs font-bold text-gray-500 uppercase">Logo da Assinatura</label>
                                        <div className="flex items-center gap-4 p-3 border rounded-xl bg-gray-50">
                                            <div className="w-16 h-16 rounded-full border bg-white overflow-hidden flex-shrink-0 relative group">
                                                <img
                                                    src={getImageUrl(formData.logoUrl)}
                                                    alt="Logo Preview"
                                                    className="w-full h-full object-cover"
                                                />
                                                {isUploading && (
                                                    <div className="absolute inset-0 bg-white/80 flex items-center justify-center">
                                                        <RefreshCcw size={16} className="animate-spin text-indigo-600" />
                                                    </div>
                                                )}
                                            </div>
                                            <div className="flex-1">
                                                <label className={`cursor-pointer px-4 py-2 border rounded-lg text-xs font-bold transition flex items-center gap-2 w-fit ${isUploading ? 'bg-gray-100 text-gray-400' : 'bg-white hover:bg-gray-100 text-gray-700 shadow-sm'}`}>
                                                    <Upload size={14} />
                                                    {isUploading ? `Enviando ${uploadProgress}%` : 'Alterar Logo'}
                                                    <input
                                                        type="file"
                                                        className="hidden"
                                                        accept="image/*"
                                                        onChange={handleLogoUpload}
                                                        disabled={isUploading}
                                                    />
                                                </label>
                                                <p className="text-[10px] text-gray-400 mt-1">Recomendado: imagem quadrada (ex: 400x400px)</p>
                                            </div>
                                        </div>
                                    </div>
                                    <div>
                                        <label className="block text-xs font-bold text-gray-500 uppercase mb-1">WhatsApp</label>
                                        <input
                                            type="text" required value={formData.whatsapp}
                                            onChange={e => setFormData({ ...formData, whatsapp: e.target.value })}
                                            className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none text-sm"
                                        />
                                    </div>
                                    <div>
                                        <label className="block text-xs font-bold text-gray-500 uppercase mb-1">E-mail de Contato</label>
                                        <input
                                            type="email" required value={formData.email}
                                            onChange={e => setFormData({ ...formData, email: e.target.value })}
                                            className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none text-sm"
                                        />
                                    </div>
                                </div>
                            </div>
                        </div>

                        <div className="space-y-4">
                            <h4 className="font-bold text-gray-800 border-b pb-2">Configurações de Loja</h4>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Nome da Loja</label>
                                    <input
                                        type="text" required value={formData.storeName}
                                        onChange={e => setFormData({ ...formData, storeName: e.target.value })}
                                        className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none text-sm"
                                    />
                                </div>
                                <div>
                                    <label className="block text-xs font-bold text-gray-500 uppercase mb-1">URL da Loja</label>
                                    <input
                                        type="url" required value={formData.storeUrl}
                                        onChange={e => setFormData({ ...formData, storeUrl: e.target.value })}
                                        className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none text-sm"
                                    />
                                </div>
                            </div>
                            <div>
                                <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Lema / Frase de Efeito</label>
                                <input
                                    type="text" required value={formData.motto}
                                    onChange={e => setFormData({ ...formData, motto: e.target.value })}
                                    className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none text-sm"
                                />
                            </div>
                        </div>

                        <div className="flex justify-between items-center pt-4 border-t">
                            {selectedId && (
                                <button
                                    type="button"
                                    onClick={() => handleDelete(selectedId)}
                                    className="flex items-center gap-2 text-red-500 hover:text-red-700 font-bold text-sm transition"
                                >
                                    <Trash2 size={18} /> Excluir Assinatura
                                </button>
                            )}
                            <div className="flex gap-3 ml-auto">
                                <button
                                    type="submit"
                                    disabled={isSaving}
                                    className="px-8 py-2 bg-indigo-600 text-white font-bold rounded-lg shadow-lg hover:bg-indigo-700 transition flex items-center gap-2 disabled:bg-indigo-400"
                                >
                                    {isSaving ? <CheckCircle className="animate-pulse" /> : <Save size={20} />}
                                    {isSaving ? 'Salvando...' : 'Salvar Assinatura'}
                                </button>
                            </div>
                        </div>
                    </form>
                </div>
            </div>
        </div>
    );
}

import { render, screen, fireEvent, waitFor } from '../../test-utils';
import { OrdersPage } from './OrdersList';
import { OrderService } from '../../services/OrderService';
import { describe, it, expect, vi, beforeEach } from 'vitest';

// Mock OrderService
vi.mock('../../services/OrderService', () => ({
    OrderService: {
        getAll: vi.fn(),
        cancel: vi.fn(),
    }
}));

describe('OrdersPage Component', () => {
    const mockOrders = [
        { id: 'ORD1', customerName: 'Cliente 1', total: 100, status: 'PAID', createdAt: '2024-02-10T10:00:00Z' },
        { id: 'ORD2', customerName: 'Cliente 2', total: 50, status: 'PENDING', createdAt: '2024-02-10T11:00:00Z' }
    ];

    beforeEach(() => {
        vi.clearAllMocks();
        (OrderService.getAll as any).mockResolvedValue(mockOrders);
    });

    it('should render orders list correctly', async () => {
        render(<OrdersPage />);

        expect(await screen.findByText('Cliente 1')).toBeInTheDocument();
        expect(screen.getByText('Cliente 2')).toBeInTheDocument();
        // Check for presence of formatted total (ignoring exact locale formatting)
        expect(screen.getByText(/100,00/)).toBeInTheDocument();
        expect(screen.getByText('PAID')).toBeInTheDocument();
        expect(screen.getByText('PENDING')).toBeInTheDocument();
    });

    it('should open cancel modal and cancel order', async () => {
        (OrderService.cancel as any).mockResolvedValue({});
        render(<OrdersPage />);

        const cancelButtons = await screen.findAllByTitle('Cancelar Pedido');
        fireEvent.click(cancelButtons[1]); // Cancel ORD2 (PENDING)

        expect(screen.getByText('Cancelar Pedido')).toBeInTheDocument();

        const textArea = screen.getByRole('textbox');
        fireEvent.change(textArea, { target: { value: 'Motivo de teste' } });

        const confirmButton = screen.getByText('Confirmar Cancelamento');
        fireEvent.click(confirmButton);

        await waitFor(() => {
            expect(OrderService.cancel).toHaveBeenCalledWith('ORD2', 'Motivo de teste');
            // Check if status updated in the list
            const cancelledStatus = screen.getAllByText('CANCELED');
            expect(cancelledStatus.length).toBeGreaterThan(0);
        });
    });
});

import { render, screen, fireEvent, waitFor } from '../../test-utils';
import { ProductForm } from './ProductForm';
import { CategoryService } from '../../services/CategoryService';
import { ProductService } from '../../services/ProductService';
import { describe, it, expect, vi, beforeEach } from 'vitest';

describe('ProductForm Component', () => {
    const mockCategories = [
        { id: '1', name: 'Velas' },
        { id: '2', name: 'Incensos' }
    ];

    beforeEach(() => {
        vi.clearAllMocks();
        (CategoryService.getAll as any).mockResolvedValue(mockCategories);
    });

    it('should render form fields correctly', async () => {
        render(<ProductForm />);

        expect(await screen.findByText('Novo Produto')).toBeInTheDocument();
        expect(screen.getByPlaceholderText('Ex: Camiseta Branca')).toBeInTheDocument();
        expect(screen.getByLabelText('Preço Base (R$)')).toBeInTheDocument();
        expect(screen.getByLabelText('Categoria')).toBeInTheDocument();
    });

    it('should show validation errors for empty fields', async () => {
        render(<ProductForm />);

        const saveButton = await screen.findByRole('button', { name: /Salvar Produto/i });
        fireEvent.click(saveButton);

        expect(await screen.findByText('Título muito curto')).toBeInTheDocument();
        expect(await screen.findByText('Categoria obrigatória')).toBeInTheDocument();
    });

    it('should submit form successfully with valid data', async () => {
        (ProductService.create as any).mockResolvedValueOnce({});

        render(<ProductForm />);

        // Wait for categories to load
        await screen.findByText('Velas');

        fireEvent.change(screen.getByPlaceholderText('Ex: Camiseta Branca'), { target: { value: 'Vela Teste' } });
        fireEvent.change(screen.getByLabelText('Preço Base (R$)'), { target: { value: '50' } });
        fireEvent.change(screen.getByLabelText('Estoque Total'), { target: { value: '10' } });
        fireEvent.change(screen.getByLabelText('Categoria'), { target: { value: '1' } });

        const saveButton = screen.getByRole('button', { name: /Salvar Produto/i });
        fireEvent.click(saveButton);

        await waitFor(() => {
            expect(ProductService.create).toHaveBeenCalledWith(expect.objectContaining({
                title: 'Vela Teste',
                price: 50,
                stock: 10,
                category: '1'
            }));
        });
    });
});

import { useState, useEffect } from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { useNavigate, useParams } from 'react-router-dom';
import { ProductService } from '../../services/ProductService';
import { CategoryService } from '../../services/CategoryService';
import { VariantsManager } from '../../components/products/VariantsManager';
import { MediaGallery } from '../../components/products/MediaGallery';
import { CreatableCategorySelect } from '../../components/products/CreatableCategorySelect';
import { ChevronLeft, Save, Plus, Wand2 } from 'lucide-react';
import type { ProductMedia, ProductVariant } from '../../types/product';
import type { Category } from '../../types/category';
import type { AdminServiceProvider } from '../../types/store-settings';
import { AdminProviderService } from '../../services/AdminProviderService';
import Button from '../../components/ui/Button';
import { useToast } from '../../context/ToastContext';

const schema = z.object({
  title: z.string().min(3, 'Título muito curto'),
  description: z.string(),
  category: z.string().min(1, 'Categoria obrigatória'),
  tenantId: z.string(),
  marketplaceIds: z.array(z.string()).optional(),
  weight: z.coerce.number().optional().default(0),
  height: z.coerce.number().optional().default(0),
  width: z.coerce.number().optional().default(0),
  length: z.coerce.number().optional().default(0),
});

type FormData = z.infer<typeof schema>;

export function ProductForm() {
  const navigate = useNavigate();
  const { id } = useParams();
  const { addToast } = useToast();

  // Product-level states
  const [categories, setCategories] = useState<Category[]>([]);
  const [marketplaces, setMarketplaces] = useState<AdminServiceProvider[]>([]);
  const [selectedMarketplaces, setSelectedMarketplaces] = useState<string[]>([]);
  const [allMedia, setAllMedia] = useState<ProductMedia[]>([]);

  // Step-by-step Variant states
  const [variants, setVariants] = useState<ProductVariant[]>([]);
  const [currentMedia, setCurrentMedia] = useState<ProductMedia[]>([]);
  const [newCategoryName, setNewCategoryName] = useState<string | null>(null); // holds the typed name if dynamic
  const [editingVariantId, setEditingVariantId] = useState<string | null>(null);

  const [variantInput, setVariantInput] = useState({
    color: '',
    size: '',
    sku: '',
    originalPrice: '',
    price: '',
    stock: ''
  });

  const [isGeneratingAI, setIsGeneratingAI] = useState(false);
  const [isSaving, setIsSaving] = useState(false);

  const { register, handleSubmit, reset, setValue, getValues, watch, formState: { errors } } = useForm<FormData>({
    resolver: zodResolver(schema) as any,
    defaultValues: {
      tenantId: '1',
      weight: 0,
      height: 0,
      width: 0,
      length: 0,
      marketplaceIds: [],
    }
  });

  const CHANNEL_ICONS: Record<string, string> = {
    'mercadolivre': 'https://http2.mlstatic.com/frontend-assets/ui-navigation/5.21.3/mercadolibre/favicon.svg',
    'tiktok': 'https://upload.wikimedia.org/wikipedia/en/a/a9/TikTok_logo.svg',
    'LOJA_VIRTUAL': '/logo.png'
  };

  useEffect(() => {
    loadCategories();
    loadMarketplaces();
    if (id) {
      loadProduct();
    } else {
      // Limpa TODO o estado ao criar novo produto
      reset({
        title: '',
        description: '',
        category: '',
        tenantId: '1',
        marketplaceIds: [],
      });
      setVariants([]);
      setCurrentMedia([]);
      setAllMedia([]);
      setSelectedMarketplaces([]);
      setEditingVariantId(null);
      setNewCategoryName(null);
      setVariantInput({ color: '', size: '', sku: '', originalPrice: '', price: '', stock: '' });
    }
  }, [id]);

  const loadMarketplaces = async () => {
    try {
      const data = await AdminProviderService.listProviders();
      const dbMarketplaces = data.filter(p => p.serviceType === 'MARKETPLACE' && p.enabled);
      setMarketplaces(dbMarketplaces);

      if (!id) {
        const ecommerce = dbMarketplaces.find(p => p.code === 'LOJA_VIRTUAL');
        if (ecommerce) {
          setSelectedMarketplaces([ecommerce.id]);
        }
      }
    } catch (error) {
      console.error('Erro ao carregar marketplaces', error);
    }
  };

  const loadCategories = async () => {
    try {
      const data = await CategoryService.getAll();
      setCategories(data);
    } catch (error) {
      console.error('Erro ao carregar categorias:', error);
    }
  };

  const loadProduct = async () => {
    if (!id) return;
    try {
      const product = await ProductService.getById(id);
      reset({
        title: product.title || (product as any).name || '',
        description: product.description || '',
        category: (product as any).categoryId || product.category || '',
        tenantId: product.tenantId || '1',
        marketplaceIds: product.marketplaceIds || [],
        weight: (product as any).weight || product.dimensions?.weight || 0,
        height: (product as any).height || product.dimensions?.height || 0,
        width: (product as any).width || product.dimensions?.width || 0,
        length: (product as any).length || product.dimensions?.length || 0,
      });
      if (product.variants) setVariants(product.variants);
      if (product.media) {
        setAllMedia(product.media);
      }
      if (product.marketplaceIds) setSelectedMarketplaces(product.marketplaceIds);
    } catch (error) {
      console.error('Erro ao carregar produto', error);
    }
  };

  const handleGenerateDescription = async () => {
    const title = getValues('title');
    if (!title) return addToast('Preencha o título do formulário primeiro.', 'info');

    const mainImage = currentMedia.find(m => m.isMain) || currentMedia[0];
    const imageUrl = mainImage ? mainImage.url : undefined;

    // Frontend validation to capture missing image before sending to API 
    // (though the Backend will also validate this as per requirements)
    if (!imageUrl) {
      addToast('É necessário adicionar uma imagem da variante atual para gerar as informações via IA.', 'info');
      return;
    }

    setIsGeneratingAI(true);
    try {
      const productInfo = await ProductService.generateDescription(title, imageUrl);
      if (!productInfo || !productInfo.description) throw new Error('Descrição vazia retornada.');
      setValue('description', productInfo.description);
      if (productInfo.title && productInfo.title !== title) {
        setValue('title', productInfo.title);
      }
    } catch (error: any) {
      console.error('Erro IA:', error);
      const msg = error.response?.data?.error || error.response?.data?.message || error.message || 'Erro desconhecido.';
      if (confirm(`Atenção: ${msg}\n\nVerifique as imagens anexadas ou se a Chave IA é válida nas Configurações.\nDeseja ir para configurações agora?`)) {
        navigate('/settings/ai');
      }
    } finally {
      setIsGeneratingAI(false);
    }
  };

  const handleEditVariant = (variant: ProductVariant) => {
    setEditingVariantId(variant.id!);
    setVariantInput({
      color: variant.attributes?.color || '',
      size: variant.attributes?.size || '',
      sku: variant.sku || '',
      originalPrice: variant.originalPrice?.toString() || '',
      price: variant.price?.toString() || '',
      stock: variant.stock?.toString() || ''
    });

    if (variant.media && variant.media.length > 0) {
      setCurrentMedia(variant.media);
    } else if (variant.imageUrl) {
      const existingMedia = allMedia.find(m => m.url === variant.imageUrl);
      if (existingMedia) {
        setCurrentMedia([{ ...existingMedia, isMain: true }]);
      } else {
        setCurrentMedia([{ id: variant.imageUrl, url: variant.imageUrl, isMain: true, type: 'IMAGE' as any }]);
      }
    } else {
      setCurrentMedia([]);
    }

    // Scroll up to Variant inputs smoothly
    window.scrollTo({ top: 300, behavior: 'smooth' });
  };

  const handleAddVariant = () => {
    // Inheritance logic
    const firstVariant = variants.length > 0 ? variants[0] : null;

    const finalPrice = variantInput.price === ''
      ? (firstVariant ? firstVariant.price : 0)
      : Number(variantInput.price);

    const finalOriginalPrice = variantInput.originalPrice === ''
      ? (firstVariant ? firstVariant.originalPrice : undefined)
      : Number(variantInput.originalPrice) || undefined;

    if (finalOriginalPrice && finalPrice >= finalOriginalPrice) {
      addToast("O Preço promocional deve ser menor ou igual ao Preço Original.", "error");
      return;
    }

    const finalStock = variantInput.stock === ''
      ? (firstVariant ? firstVariant.stock : 0)
      : Number(variantInput.stock);

    const finalColor = variantInput.color.trim() === ''
      ? (firstVariant ? firstVariant.attributes?.color : '')
      : variantInput.color.trim();

    const finalSize = variantInput.size.trim() === ''
      ? (firstVariant ? firstVariant.attributes?.size : '')
      : variantInput.size.trim();

    // Frontend validation for Variant Image (optional by user instructions, but good UX to catch before clicking "Salvar Produto")
    // "O Frontend não deve fazer a validação rígida de imagem no client-side; deve apenas capturar o erro da API"
    // So we allow adding without image to the list. The backend will reject when "Salvar Produto" is hit.

    const mainImage = currentMedia.find(m => m.isMain) || currentMedia[0];

    const variant: ProductVariant = {
      id: editingVariantId || crypto.randomUUID(),
      sku: variantInput.sku.trim(), // SKU is auto-generated by backend if empty
      price: finalPrice,
      originalPrice: finalOriginalPrice,
      stock: finalStock,
      attributes: { size: finalSize || 'Unico', color: finalColor || '' },
      imageUrl: mainImage ? mainImage.url : '',
      media: currentMedia.map(m => ({ ...m }))
    };

    // Store media securely for final payload
    setAllMedia(prev => {
      const newArr = [...prev];
      for (const m of currentMedia) {
        if (!newArr.some(ext => ext.url === m.url)) newArr.push(m);
      }
      return newArr;
    });

    if (editingVariantId) {
      setVariants(prev => prev.map(v => v.id === editingVariantId ? variant : v));
      setEditingVariantId(null);
    } else {
      setVariants(prev => [...prev, variant]);
    }

    // Clear variant inputs and media
    setVariantInput({ color: '', size: '', sku: '', originalPrice: '', price: '', stock: '' });
    setCurrentMedia([]);
  };

  const onCategoryChange = (val: string, newName?: string) => {
    if (val.startsWith('NEW_') && newName) {
      setNewCategoryName(newName);
      setValue('category', val); // Temporary ID
    } else {
      setNewCategoryName(null);
      setValue('category', val);
    }
  };

  const onSubmit = async (data: FormData) => {
    setIsSaving(true);
    try {
      let finalCategoryId = data.category;

      // Handle dynamic category creation right before saving the product
      if (finalCategoryId.startsWith('NEW_') && newCategoryName) {
        try {
          const createdCat = await CategoryService.create({ name: newCategoryName, active: true });
          finalCategoryId = createdCat.id;
        } catch (e) {
          console.error("Falha ao criar nova categoria dynamique", e);
          addToast('Erro ao criar a nova categoria. Tente novamente.', 'error');
          setIsSaving(false);
          return;
        }
      }

      // If user forgot to add variant but filled something, alert them or auto add?
      if (variants.length === 0) {
        if (!confirm("Você não adicionou nenhuma variante à lista clicando no botão 'Adicionar'. Deseja salvar um produto sem variantes ou voltar e clicar em Adicionar?")) {
          setIsSaving(false);
          return;
        }
      }

      // Preparar mídias para envio
      let sortedMedia = [...allMedia];

      // Se não houver capa definida explicitamente no produto pai, 
      // tenta pegar da primeira variante que tenha imagem
      const hasExplicitMain = sortedMedia.some(m => m.isMain);
      if (!hasExplicitMain && variants.length > 0) {
        const firstVariantWithMedia = variants.find(v => v.media && v.media.length > 0);
        if (firstVariantWithMedia && firstVariantWithMedia.media && firstVariantWithMedia.media[0]) {
          // Encontra essa mídia no allMedia (pela URL ou ID se possível) ou adiciona se não estiver
          const variantMainMediaUrl = firstVariantWithMedia.media[0].url;
          const mediaIndex = sortedMedia.findIndex(m => m.url === variantMainMediaUrl);

          if (mediaIndex !== -1) {
            sortedMedia = sortedMedia.map((m, i) => ({ ...m, isMain: i === mediaIndex }));
          }
        }
      }

      // As per backend logic, product base fields takes the first variant if price/stock are 0 
      const basePrice = variants.length > 0 ? variants[0].price : 0;
      const baseOriginalPrice = variants.length > 0 ? variants[0].originalPrice : undefined;
      const payload: any = {
        ...data,
        category: finalCategoryId,
        price: basePrice,
        originalPrice: baseOriginalPrice,
        active: true,
        variants,
        media: sortedMedia,
        marketplaceIds: selectedMarketplaces,
        weight: data.weight,
        height: data.height,
        width: data.width,
        length: data.length,
      };

      if (id) {
        await ProductService.update(id, payload);
      } else {
        await ProductService.create(payload);
      }
      navigate('/products');

    } catch (error: any) {
      console.error('Erro ao salvar produto', error);
      const msg = error.response?.data?.error || error.response?.data?.message || error.message || 'Erro interno da API';
      addToast(`Erro ao ${id ? 'atualizar' : 'criar'} produto: ${msg}`, 'error');
    } finally {
      setIsSaving(false);
    }
  };

  return (
    <div className="space-y-6 pb-20">
      <div className="flex items-center gap-4">
        <button onClick={() => navigate('/products')} className="p-2 hover:bg-gray-100 rounded-full">
          <ChevronLeft />
        </button>
        <div>
          <h1 className="text-2xl font-bold text-gray-800">{id ? 'Editar Produto' : 'Novo Produto'}</h1>
          <p className="text-gray-500">Cadastro passo-a-passo de Informações e Variantes</p>
        </div>
      </div>

      <form onSubmit={handleSubmit(onSubmit)} className="space-y-6">

        {/* Passo 1 - Mídia & Imagens */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
          <div className="mb-4 text-sm text-indigo-600 bg-indigo-50 p-3 rounded border border-indigo-100 italic">
            Para adicionar um produto com múltiplas variantes e fotos distintas: anexe primeiro as fotos de uma cor/modelo, preencha os dados abaixo e clique em <b>"Adicionar"</b>. A galeria será limpa para você subir as fotos da próxima variação! A foto principal da Categoria se torna a Capa da variante.
          </div>
          <h2 className="font-semibold text-lg text-gray-800 border-b pb-2 mb-4">Mídia & Imagens da Variante Atual</h2>
          <MediaGallery media={currentMedia} onChange={setCurrentMedia} />
        </div>

        {/* Passo 2 - Informações Básicas & Variantes */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 space-y-6">
          <h2 className="font-semibold text-lg text-gray-800 border-b pb-2">Informações Básicas & Variantes</h2>

          {/* Dados Gerais (Retidos após Adicionar) */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4 bg-gray-50 p-4 rounded border">
            <div className="col-span-2 md:col-span-1">
              <label htmlFor="title" className="block text-sm font-medium text-gray-700 mb-1">Título do Produto</label>
              <input id="title" {...register('title')} className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 bg-white" placeholder="Ex: Vestido Amarelo Ogum" />
              {errors.title && <p className="text-red-500 text-xs mt-1">{errors.title.message}</p>}
            </div>

            <div className="col-span-2 md:col-span-1">
              <label htmlFor="category" className="block text-sm font-medium text-gray-700 mb-1">Categoria</label>
              <CreatableCategorySelect
                categories={categories}
                value={watch('category')}
                onChange={onCategoryChange}
                error={errors.category?.message}
              />
            </div>

            <div className="col-span-2">
              <div className="flex justify-between items-center mb-1">
                <label htmlFor="description" className="block text-sm font-medium text-gray-700">Descrição</label>
                <Button
                  type="button"
                  onClick={handleGenerateDescription}
                  isLoading={isGeneratingAI}
                  variant="secondary"
                  size="sm"
                  className="bg-indigo-100 text-indigo-700 hover:bg-indigo-200 border-none"
                  title="Utiliza a imagem principal em anexo acima para gerar detalhes"
                >
                  <Wand2 size={14} /> {isGeneratingAI ? 'Gerando...' : 'Gerar informações por IA'}
                </Button>
              </div>
              <textarea id="description" {...register('description')} className="w-full p-2 border rounded-lg h-24 focus:ring-2 focus:ring-indigo-500 bg-white" placeholder="Descreva os detalhes gerais da peça..." />
            </div>
          </div>

          {/* Dados Específicos da Variante (Limpados após Adicionar) */}
          <div className="grid grid-cols-2 md:grid-cols-6 gap-3 pt-2">
            <div className="col-span-1 border-l-2 border-indigo-200 pl-2">
              <label className="text-xs text-gray-500 mb-1 block">Cor <span className="text-gray-400 italic font-mono">(ex: Ouro)</span></label>
              <input
                className="w-full p-2 text-sm border rounded bg-white"
                value={variantInput.color}
                onChange={e => setVariantInput({ ...variantInput, color: e.target.value })}
                placeholder="Deixe vazio p/ herdar"
              />
            </div>
            <div className="col-span-1 border-l-2 border-indigo-200 pl-2">
              <label className="text-xs text-gray-500 mb-1 block">Tamanho <span className="text-gray-400 italic font-mono">(ex: P)</span></label>
              <input
                className="w-full p-2 text-sm border rounded bg-white"
                value={variantInput.size}
                onChange={e => setVariantInput({ ...variantInput, size: e.target.value })}
                placeholder="Deixe vazio p/ herdar"
              />
            </div>
            <div className="col-span-1 border-l-2 border-amber-200 pl-2">
              <label className="text-xs text-gray-400 mb-1 block line-through">De (R$)</label>
              <input
                type="number"
                step="0.01"
                className="w-full p-2 text-sm border rounded bg-white"
                value={variantInput.originalPrice}
                onChange={e => setVariantInput({ ...variantInput, originalPrice: e.target.value })}
                placeholder="Vazio p/ herdar"
              />
            </div>
            <div className="col-span-1 border-l-2 border-amber-500 pl-2">
              <label className="text-xs text-gray-800 font-bold mb-1 block">Por (R$)</label>
              <input
                type="number"
                step="0.01"
                className="w-full p-2 text-sm border rounded bg-white"
                value={variantInput.price}
                onChange={e => setVariantInput({ ...variantInput, price: e.target.value })}
                placeholder="0.00 (ou herdar)"
              />
            </div>
            <div className="col-span-1 border-l-2 border-amber-200 pl-2">
              <label className="text-xs text-gray-500 mb-1 block">Qtde. Estoque</label>
              <input
                type="number"
                className="w-full p-2 text-sm border rounded bg-white"
                value={variantInput.stock}
                onChange={e => setVariantInput({ ...variantInput, stock: e.target.value })}
                placeholder="0 (ou herdar)"
              />
            </div>
            <div className="col-span-1 border-l-2 border-gray-200 pl-2">
              <label className="text-xs text-gray-500 mb-1 block">SKU</label>
              <input
                className="w-full p-2 text-sm border rounded bg-white"
                value={variantInput.sku}
                onChange={e => setVariantInput({ ...variantInput, sku: e.target.value })}
                placeholder="Auto"
              />
            </div>

            <div className="col-span-2 md:col-span-5 flex justify-end mt-2 items-center gap-3">
              {editingVariantId && (
                <Button
                  type="button"
                  onClick={() => {
                    setEditingVariantId(null);
                    setVariantInput({ color: '', size: '', sku: '', originalPrice: '', price: '', stock: '' });
                    setCurrentMedia([]);
                  }}
                  variant="ghost"
                >
                  Cancelar Edição
                </Button>
              )}
              <Button
                type="button"
                onClick={handleAddVariant}
                variant="primary"
              >
                {editingVariantId ? <Save size={18} /> : <Plus size={18} />}
                {editingVariantId ? 'Salvar Alteração' : 'Adicionar Variante'}
              </Button>
            </div>
          </div>

          {/* Componente Puro de Lista */}
          <div className="pt-4 border-t">
            <VariantsManager variants={variants} onChange={setVariants} onEdit={handleEditVariant} />
          </div>

        </div>

        {/* Peso e Dimensões — necessário para cálculo de frete */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 space-y-4">
          <h2 className="font-semibold text-lg text-gray-800 border-b pb-2">Peso e Dimensões</h2>
          <p className="text-sm text-gray-500">Necessário para o cálculo de frete. Informe os valores da embalagem pronta para envio.</p>
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Peso (g)</label>
              <input
                type="number"
                step="any"
                {...register('weight', { valueAsNumber: true })}
                className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 bg-white"
                placeholder="Ex: 300 ou 0.5"
              />
              {errors.weight && <p className="text-red-500 text-xs mt-1">{errors.weight.message}</p>}
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Altura (cm)</label>
              <input
                type="number"
                step="any"
                {...register('height', { valueAsNumber: true })}
                className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 bg-white"
                placeholder="Ex: 10"
              />
              {errors.height && <p className="text-red-500 text-xs mt-1">{errors.height.message}</p>}
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Largura (cm)</label>
              <input
                type="number"
                step="any"
                {...register('width', { valueAsNumber: true })}
                className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 bg-white"
                placeholder="Ex: 20"
              />
              {errors.width && <p className="text-red-500 text-xs mt-1">{errors.width.message}</p>}
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Comprimento (cm)</label>
              <input
                type="number"
                step="any"
                {...register('length', { valueAsNumber: true })}
                className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 bg-white"
                placeholder="Ex: 30"
              />
              {errors.length && <p className="text-red-500 text-xs mt-1">{errors.length.message}</p>}
            </div>
          </div>
        </div>

        {/* Canais de Vendas */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
          <h2 className="font-semibold text-lg text-gray-800 border-b pb-2 mb-4">Canais de Venda</h2>
          <div className="space-y-3">
            {marketplaces.length === 0 && <p className="text-sm text-gray-500">Nenhum canal de venda configurado.</p>}
            {marketplaces.map(mp => (
              <label key={mp.id} className="flex items-center gap-3 p-3 border rounded-xl hover:bg-gray-50 cursor-pointer transition-all">
                <input
                  type="checkbox"
                  checked={selectedMarketplaces.includes(mp.id)}
                  onChange={e => {
                    if (e.target.checked) {
                      setSelectedMarketplaces(prev => [...prev, mp.id]);
                    } else {
                      setSelectedMarketplaces(prev => prev.filter(id => id !== mp.id));
                    }
                  }}
                  className="w-5 h-5 text-indigo-600 rounded-lg border-gray-300 focus:ring-indigo-500"
                />
                <div className="w-8 h-8 flex items-center justify-center p-1 bg-white rounded-lg border border-gray-100">
                  <img
                    src={CHANNEL_ICONS[mp.code] || '/logo.png'}
                    alt={mp.name}
                    className="w-full h-full object-contain"
                  />
                </div>
                <span className="text-sm font-semibold text-gray-700">{mp.name}</span>
              </label>
            ))}
          </div>
        </div>

        {/* Action Bar / Rodapé */}
        <div className="fixed bottom-0 left-64 right-0 bg-white border-t p-4 flex justify-end gap-3 z-10 shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.05)]">
          <Button
            type="button"
            onClick={() => navigate('/products')}
            variant="secondary"
          >
            Cancelar
          </Button>
          <Button
            type="submit"
            isLoading={isSaving}
            variant="primary"
            className="bg-emerald-600 hover:bg-emerald-700 focus:ring-emerald-500 min-w-[160px]"
          >
            {!isSaving && <Save size={20} />}
            {isSaving ? 'Salvando...' : 'Salvar Produto'}
          </Button>
        </div>
      </form >
    </div >
  );
}

import { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { ProductService } from '../../services/ProductService';
import type { Product } from '../../types/product';
import { Package, Plus, Search, Edit, Trash2, Bell, Power } from 'lucide-react';
import { StockAlertService, type StockAlertSettings } from '../../services/StockAlertService';
import { calculatePriority, STOCK_COLORS, type ColorPreset } from '../../hooks/useStockAlerts';
import clsx from 'clsx';
import Skeleton from '../../components/ui/Skeleton';
import { getImageUrl } from '../../utils/imageUtils';

export function ProductsPage() {
  // Inicializa com array vazio para evitar erro no primeiro render
  const [products, setProducts] = useState<Product[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [stockSort, setStockSort] = useState<'none' | 'asc' | 'desc'>('none');
  const [stockFilter, setStockFilter] = useState<'all' | 'out' | 'low'>('all');
  const [alertSettings, setAlertSettings] = useState<StockAlertSettings | null>(null);
  const navigate = useNavigate();

  useEffect(() => {
    loadProducts();
  }, []);

  const loadProducts = async () => {
    try {
      setLoading(true);
      const [data, settings] = await Promise.all([
        ProductService.getAll(),
        StockAlertService.getSettings()
      ]);

      setAlertSettings(settings);

      // BLINDAGEM: Verifica se é realmente um array antes de setar
      if (Array.isArray(data)) {
        setProducts(data);
      } else {
        console.error('API retornou formato inválido (esperado array):', data);
        setProducts([]); // Fallback para lista vazia
      }
    } catch (error) {
      console.error('Erro ao carregar produtos', error);
      setProducts([]); // Fallback em caso de erro de rede
    } finally {
      setLoading(false);
    }
  };

  const handleToggleAlert = async (id: string) => {
    try {
      // Agora esperamos a API confirmar antes de atualizar o estado local
      await ProductService.toggleAlert(id);

      setProducts(prev => prev.map(p =>
        p.id === id ? { ...p, alertEnabled: !p.alertEnabled } : p
      ));
    } catch (error: any) {
      console.error('Erro ao atualizar alerta', error);
      if (error.response?.status === 404) {
        alert('Produto não encontrado ou funcionalidade indisponível.');
      } else {
        alert('Erro ao atualizar alerta. Tente novamente.');
      }
    }
  };

  const handleToggleActive = async (id: string, currentStatus: boolean | undefined) => {
    try {
      await ProductService.toggleActive(id);
      setProducts(prev => prev.map(p =>
        p.id === id ? { ...p, active: !currentStatus } : p
      ));
    } catch (error) {
      console.error('Erro ao alternar status do produto', error);
      alert('Erro ao alterar o status do produto. Tente novamente.');
    }
  };

  const handleEdit = (id: string) => {
    navigate(`/products/edit/${id}`);
  };

  const handleDelete = async (id: string) => {
    if (!confirm('Tem certeza que deseja excluir este produto? Esta ação não pode ser desfeita.')) return;
    try {
      await ProductService.delete(id);
      await loadProducts();
    } catch (error) {
      console.error('Erro ao excluir produto', error);
      // O overlay global cuidará do feedback de erro via interceptor se necessário, 
      // mas mantemos o alert por precaução
      alert('Erro ao excluir produto. Verifique se não há dependências.');
    }
  };

  // Garante que products é um array antes de filtrar
  const safeProducts = Array.isArray(products) ? products : [];

  const filteredProducts = safeProducts
    .filter(p => {
      const matchesSearch = p.title ? p.title.toLowerCase().includes(searchTerm.toLowerCase()) : false;
      const matchesStockFilter =
        stockFilter === 'all' ? true :
          stockFilter === 'out' ? (p.stock <= 0) :
            stockFilter === 'low' ? (p.stock > 0 && p.stock <= (alertSettings?.threshold || 10)) : true;

      return matchesSearch && matchesStockFilter;
    })
    .sort((a, b) => {
      if (stockSort === 'asc') return (a.stock || 0) - (b.stock || 0);
      if (stockSort === 'desc') return (b.stock || 0) - (a.stock || 0);
      return 0;
    });

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-2xl font-bold text-gray-800">Produtos</h1>
          <p className="text-gray-500">Gerencie o catálogo da loja</p>
        </div>
        <button
          onClick={() => navigate('/products/new')}
          className="flex items-center gap-2 bg-indigo-600 text-white px-4 py-2 rounded-lg hover:bg-indigo-700 transition"
        >
          <Plus size={20} />
          Novo Produto
        </button>
      </div>

      <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-100 flex flex-col md:flex-row gap-4">
        <div className="flex-1 relative">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={20} />
          <input
            type="text"
            placeholder="Buscar por nome..."
            className="w-full pl-10 pr-4 py-2 border rounded-lg outline-none focus:ring-2 focus:ring-indigo-500"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="flex gap-4">
          <select
            className="px-4 py-2 border rounded-lg outline-none focus:ring-2 focus:ring-indigo-500 bg-white text-sm text-gray-700 font-medium"
            value={stockFilter}
            onChange={(e) => setStockFilter(e.target.value as any)}
          >
            <option value="all">📦 Todos os Estoques</option>
            <option value="out">🚫 Sem Estoque</option>
            <option value="low">⚠️ Estoque Baixo (&lt;10)</option>
          </select>

          <select
            className="px-4 py-2 border rounded-lg outline-none focus:ring-2 focus:ring-indigo-500 bg-white text-sm text-gray-700 font-medium"
            value={stockSort}
            onChange={(e) => setStockSort(e.target.value as any)}
          >
            <option value="none">⇅ Ordenação Padrão</option>
            <option value="asc">📉 Estoque: Menor primeiro</option>
            <option value="desc">📈 Estoque: Maior primeiro</option>
          </select>
        </div>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-gray-50 border-b">
            <tr>
              <th className="p-4 text-sm font-semibold text-gray-600">Produto</th>
              <th className="p-4 text-sm font-semibold text-gray-600">Preço</th>
              <th className="p-4 text-sm font-semibold text-gray-600">Estoque</th>
              <th className="p-4 text-sm font-semibold text-gray-600">Status</th>
              <th className="p-4 text-sm font-semibold text-gray-600 text-right">Ações</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-100">
            {loading ? (
              [...Array(5)].map((_, i) => (
                <tr key={i}>
                  <td className="p-4">
                    <div className="flex items-center gap-3">
                      <Skeleton className="w-10 h-10" />
                      <div className="space-y-2">
                        <Skeleton className="h-4 w-32" variant="text" />
                        <Skeleton className="h-3 w-48" variant="text" />
                      </div>
                    </div>
                  </td>
                  <td className="p-4"><Skeleton className="h-4 w-20" variant="text" /></td>
                  <td className="p-4"><Skeleton className="h-6 w-16" variant="rect" /></td>
                  <td className="p-4"><Skeleton className="h-2 w-2 rounded-full" variant="circle" /></td>
                  <td className="p-4 text-right flex justify-end gap-2 text-gray-200">
                    <Skeleton className="h-8 w-8" variant="circle" />
                    <Skeleton className="h-8 w-8" variant="circle" />
                    <Skeleton className="h-8 w-8" variant="circle" />
                  </td>
                </tr>
              ))
            ) : filteredProducts.length === 0 ? (
              <tr>
                <td colSpan={5} className="p-8 text-center text-gray-500">
                  Nenhum produto encontrado.
                </td>
              </tr>
            ) : (
              filteredProducts.map((product) => (
                <tr key={product.id} className="hover:bg-gray-50 transition">
                  <td className="p-4">
                    <div className="flex items-center gap-3">
                      <div className="w-10 h-10 bg-gray-200 rounded-lg flex items-center justify-center text-gray-500 overflow-hidden border border-gray-100 flex-shrink-0">
                        {(() => {
                          const mainImg = product.media?.find(m => m.isMain)?.url || product.media?.[0]?.url;
                          const variantImg = product.variants?.[0]?.imageUrl || product.variants?.[0]?.media?.[0]?.url;
                          // @ts-ignore
                          const rawImg = Array.isArray(product.images) && product.images.length > 0 ? product.images[0] : null;
                          const finalImg = mainImg || variantImg || rawImg;

                          return finalImg ? (
                            <img
                              src={getImageUrl(finalImg)}
                              alt={product.title}
                              className="w-full h-full object-cover"
                              onError={(e) => {
                                (e.target as HTMLImageElement).style.display = 'none';
                                (e.target as HTMLImageElement).parentElement!.classList.add('bg-gray-200');
                                (e.target as HTMLImageElement).parentElement!.innerHTML = '<svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="lucide lucide-package"><path d="m7.5 4.27 9 5.15"/><path d="M21 8a2 2 0 0 0-1-1.73l-7-4a2 2 0 0 0-2 0l-7 4A2 2 0 0 0 3 8v8a2 2 0 0 0 1 1.73l7 4a2 2 0 0 0 2 0l7-4A2 2 0 0 0 21 16Z"/><path d="m3.3 7 8.7 5 8.7-5"/><path d="M12 22v-10"/></svg>';
                              }}
                            />
                          ) : (
                            <Package size={20} />
                          );
                        })()}
                      </div>
                      <div className="overflow-hidden">
                        <p
                          className="font-medium text-gray-800 truncate"
                          style={{ maxWidth: '250px' }}
                          title={product.title}
                        >
                          {product.title}
                        </p>
                        <p className="text-xs text-gray-500 truncate max-w-[250px]">{product.description}</p>
                      </div>
                    </div>
                  </td>
                  <td className="p-4 font-medium text-gray-700">
                    {product.price ? new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(product.price) : 'R$ 0,00'}
                  </td>
                  <td className="p-4">
                    {product.stock <= 0 ? (
                      <span className="px-2 py-1 rounded-full text-xs font-bold bg-gray-100 text-gray-400 uppercase border border-gray-200">
                        Sem Estoque
                      </span>
                    ) : (() => {
                      const priority = calculatePriority(product.stock || 0, alertSettings);
                      const preset = priority ? STOCK_COLORS[priority.color as ColorPreset] : null;

                      return (
                        <span className={clsx(
                          "px-2 py-1 rounded-full text-xs font-bold transition-all",
                          preset ? clsx(preset.bg, preset.text, product.alertEnabled && "animate-pulse") : "bg-green-100 text-green-700"
                        )}>
                          {product.stock || 0} un
                        </span>
                      );
                    })()}
                  </td>
                  <td className="p-4">
                    <span className={`inline-block w-2 h-2 rounded-full ${product.active ? 'bg-green-500' : 'bg-gray-300'}`} />
                  </td>
                  <td className="p-4 text-right flex justify-end gap-2">
                    <button
                      onClick={() => handleToggleActive(product.id, product.active)}
                      className={`transition ${product.active ? 'text-green-500 hover:text-green-600' : 'text-gray-300 hover:text-gray-500'}`}
                      title={product.active ? "Desativar Produto" : "Ativar Produto"}
                    >
                      <Power size={18} />
                    </button>
                    <button
                      onClick={() => handleToggleAlert(product.id)}
                      className={`transition ${product.alertEnabled ? 'text-yellow-500 hover:text-yellow-600' : 'text-gray-300 hover:text-gray-500'}`}
                      title={product.alertEnabled ? "Alerta de Estoque Ativo" : "Ativar Alerta de Estoque"}
                    >
                      <Bell size={18} fill={product.alertEnabled ? "currentColor" : "none"} />
                    </button>
                    <button
                      onClick={() => handleEdit(product.id)}
                      className="text-gray-400 hover:text-indigo-600 transition"
                      title="Editar Produto"
                    >
                      <Edit size={18} />
                    </button>
                    <button
                      onClick={() => handleDelete(product.id)}
                      className="text-gray-400 hover:text-red-600 transition"
                      title="Excluir Produto"
                    >
                      <Trash2 size={18} />
                    </button>
                  </td>
                </tr>
              )
              ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { Save, AlertCircle, Zap } from 'lucide-react';
import { api } from '../../api/axios';

interface AiConfigFormData {
    nomeIa: string;
    apiKey: string;
    prePrompt: string;
}

export function AiConfigPage() {
    const [isLoading, setIsLoading] = useState(false);
    const [successMsg, setSuccessMsg] = useState('');
    const [errorMsg, setErrorMsg] = useState('');

    const [formData, setFormData] = useState<AiConfigFormData>({
        nomeIa: 'Gemini',
        apiKey: '',
        prePrompt: 'Gere um título otimizado e uma descrição atrativa para o seguinte produto. Retorne apenas JSON com as chaves "title" e "description".'
    });

    useEffect(() => {
        loadConfig();
    }, []);

    const loadConfig = async () => {
        try {
            setIsLoading(true);
            const { data } = await api.get('/configs/ai');
            const geminiConfig = Array.isArray(data) ? data.find((c: any) => c.nomeIa === 'Gemini') : undefined;

            if (geminiConfig) {
                setFormData({
                    nomeIa: geminiConfig.nomeIa,
                    apiKey: geminiConfig.apiKey,
                    prePrompt: geminiConfig.prePrompt || formData.prePrompt
                });
            }
        } catch (error) {
            console.error('Erro ao carregar configurações de IA:', error);
        } finally {
            setIsLoading(false);
        }
    };

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
        const { name, value } = e.target;
        setFormData(prev => ({ ...prev, [name]: value }));
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setSuccessMsg('');
        setErrorMsg('');
        setIsLoading(true);

        try {
            await api.post('/configs/ai', formData);
            setSuccessMsg('Configurações salvas com sucesso!');
        } catch (error: any) {
            console.error('Erro ao salvar configuração de IA:', error);
            setErrorMsg(error.response?.data?.message || 'Erro ao salvar configuração.');
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className="space-y-6">
            <div className="flex justify-between items-center">
                <div>
                    <h1 className="text-2xl font-bold text-gray-900">Inteligência Artificial</h1>
                    <p className="mt-1 text-sm text-gray-500">
                        Configure as chaves e prompts para geração automática de conteúdo.
                    </p>
                </div>
            </div>

            <div className="bg-white rounded-lg shadow-sm border border-gray-200">
                <form onSubmit={handleSubmit} className="p-6 space-y-6">

                    {successMsg && (
                        <div className="p-4 bg-green-50 border border-green-200 rounded-md flex items-start">
                            <div className="ml-3 flex-1">
                                <p className="text-sm text-green-700">{successMsg}</p>
                            </div>
                        </div>
                    )}

                    {errorMsg && (
                        <div className="p-4 bg-red-50 border border-red-200 rounded-md flex items-start">
                            <AlertCircle className="w-5 h-5 text-red-500 mt-0.5" />
                            <div className="ml-3 flex-1">
                                <h3 className="text-sm font-medium text-red-800">Erro</h3>
                                <p className="text-sm text-red-700 mt-1">{errorMsg}</p>
                            </div>
                        </div>
                    )}

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">
                                Nome da IA
                            </label>
                            <input
                                type="text"
                                name="nomeIa"
                                value={formData.nomeIa}
                                disabled
                                className="w-full px-4 py-2 bg-gray-50 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all text-gray-500"
                            />
                            <p className="mt-1 text-xs text-gray-500">
                                O sistema utiliza a integração com o Google Gemini.
                            </p>
                        </div>

                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">
                                API Key <span className="text-red-500">*</span>
                            </label>
                            <div className="relative">
                                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                                    <Zap className="h-5 w-5 text-gray-400" />
                                </div>
                                <input
                                    type="password"
                                    name="apiKey"
                                    value={formData.apiKey}
                                    onChange={handleChange}
                                    required
                                    placeholder="AIzaSyB..."
                                    className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all"
                                />
                            </div>
                            <p className="mt-1 text-xs text-gray-500">
                                Obtenha sua chave no Google AI Studio.
                            </p>
                        </div>

                        <div className="md:col-span-2">
                            <label className="block text-sm font-medium text-gray-700 mb-1">
                                Pre-prompt Baseline
                            </label>
                            <textarea
                                name="prePrompt"
                                rows={4}
                                value={formData.prePrompt}
                                onChange={handleChange}
                                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all"
                                placeholder="Ex: Gere um título e uma descrição atrativa para..."
                            />
                            <p className="mt-1 text-xs text-gray-500">
                                Instruções básicas enviadas para a IA antes de enviar o título e a imagem do produto.
                                Importante manter a instrução de retorno em JSON.
                            </p>
                        </div>
                    </div>

                    <div className="flex justify-end pt-4 border-t border-gray-100">
                        <button
                            type="submit"
                            disabled={isLoading}
                            className="px-6 py-2 bg-indigo-600 text-white font-medium rounded-lg hover:bg-indigo-700 focus:ring-4 focus:ring-indigo-100 transition-colors flex items-center gap-2 disabled:bg-indigo-400"
                        >
                            <Save size={20} />
                            {isLoading ? 'Salvando...' : 'Salvar Configurações'}
                        </button>
                    </div>
                </form>
            </div>
        </div>
    );
}

