import { useState, useEffect } from 'react';
import { Truck, AlertCircle, Plus, LayoutGrid, ShieldCheck, Trash2, Code, Save } from 'lucide-react';

import { AdminProviderService } from '../../services/AdminProviderService';
import type { AdminServiceProvider } from '../../types/store-settings';
import { MelhorEnvioConfig } from '../../components/shipping/MelhorEnvioConfig';
import { MandaBemConfig } from '../../components/shipping/MandaBemConfig';
import { J3FlexConfig } from '../../components/shipping/J3FlexConfig';
import BaseModal from '../../components/ui/BaseModal';
import Button from '../../components/ui/Button';
import { useToast } from '../../context/ToastContext';

const RECOMMENDED_PROVIDERS = [
    { name: 'Melhor Envio', code: 'MELHOR_ENVIO', driverKey: 'shipping.melhorenvio', icon: '📦' },
    { name: 'J3 Flex', code: 'J3_FLEX', driverKey: 'shipping.j3flex', icon: '🚚' },
    { name: 'Manda Bem', code: 'MANDA_BEM', driverKey: 'shipping.mandabem', icon: '🚚' },
];

export function ShippingPage() {
    const [providers, setProviders] = useState<AdminServiceProvider[]>([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);
    const [editingProvider, setEditingProvider] = useState<AdminServiceProvider | null>(null);
    const [configData, setConfigData] = useState<any>({});
    const [isAddModalOpen, setIsAddModalOpen] = useState(false);
    const [newProvider, setNewProvider] = useState({ name: '', code: '', driverKey: '' });
    const { addToast } = useToast();

    useEffect(() => {
        loadData();
    }, []);

    const loadData = async () => {
        try {
            setLoading(true);
            const data = await AdminProviderService.listProviders();
            setProviders(data.filter(p => p.serviceType === 'SHIPPING'));
            setError(null);
        } catch (err) {
            console.error(err);
            setError('Serviço de frete indisponível. Verifique os logs do backend.');
        } finally {
            setLoading(false);
        }
    };

    const handleToggle = async (id: string, currentStatus: boolean) => {
        try {
            await AdminProviderService.toggleProvider(id, !currentStatus);
            setProviders((prev: AdminServiceProvider[]) => prev.map(p => p.id === id ? { ...p, enabled: !currentStatus } : p));
            addToast('Status atualizado com sucesso!', 'success');
        } catch (err) {
            addToast('Erro ao atualizar status', 'error');
        }
    };

    const handleDelete = async (id: string) => {
        if (!confirm('Tem certeza que deseja remover este provedor de frete? Todas as configurações serão perdidas.')) return;
        try {
            await AdminProviderService.deleteProvider(id);
            setProviders((prev: AdminServiceProvider[]) => prev.filter(p => p.id !== id));
            if (editingProvider?.id === id) setEditingProvider(null);
            addToast('Provedor removido!', 'success');
        } catch (err) {
            addToast('Erro ao remover provedor.', 'error');
        }
    };

    const handleAddProvider = async () => {
        if (!newProvider.name || !newProvider.code) return;
        try {
            await AdminProviderService.createProvider({
                ...newProvider,
                serviceType: 'SHIPPING',
                enabled: false,
                priority: 0,
                healthEnabled: true
            });
            setIsAddModalOpen(false);
            setNewProvider({ name: '', code: '', driverKey: '' });
            addToast('Provedor criado com sucesso!', 'success');
            loadData();
        } catch (err) {
            addToast('Erro ao criar provedor.', 'error');
        }
    };

    const handleOpenConfig = async (provider: AdminServiceProvider) => {
        if (editingProvider?.id === provider.id) {
            setEditingProvider(null);
            return;
        }
        const config = await AdminProviderService.getProviderConfig(provider.id);
        setEditingProvider(provider);
        try {
            setConfigData(config ? JSON.parse(config.configJson) : {});
        } catch (e) {
            setConfigData({});
        }
    };

    const handleSaveConfig = async () => {
        if (!editingProvider) return;
        try {
            await AdminProviderService.saveProviderConfig({
                providerId: editingProvider.id,
                configJson: JSON.stringify(configData),
                environment: 'PRODUCTION'
            });
            addToast('Configuração de frete salva!', 'success');
            setEditingProvider(null);
        } catch (err) {
            addToast('Erro ao salvar configuração.', 'error');
        }
    };

    return (
        <div className="max-w-6xl mx-auto space-y-8 p-4">
            <header className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 border-b pb-6">
                <div className="flex gap-4 items-center">
                    <div className="p-3 bg-indigo-600 rounded-2xl text-white shadow-lg shadow-indigo-100">
                        <Truck size={32} />
                    </div>
                    <div>
                        <h1 className="text-3xl font-extrabold text-gray-900 tracking-tight">Frete e Entrega</h1>
                        <div className="flex items-center gap-2 text-gray-500 mt-1">
                            <ShieldCheck size={14} className="text-green-500" />
                            <span className="text-sm">Configuração Dinâmica Ativa</span>
                        </div>
                    </div>
                </div>
                <Button
                    onClick={() => setIsAddModalOpen(true)}
                    variant="primary"
                    className="shadow-lg"
                >
                    <Plus size={20} /> Adicionar Provedor
                </Button>
            </header>

            {error && (
                <div className="bg-red-50 border-l-4 border-red-500 text-red-700 p-6 rounded-2xl flex items-center gap-4">
                    <AlertCircle size={32} />
                    <div>
                        <p className="font-bold">Erro de Sistema</p>
                        <p className="text-sm opacity-90">{error}</p>
                    </div>
                </div>
            )}

            {loading ? (
                <div className="flex flex-col items-center justify-center p-20 space-y-4">
                    <div className="w-12 h-12 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
                    <p className="text-gray-400 font-medium">Carregando serviços de logística...</p>
                </div>
            ) : (
                <div className="grid gap-6">
                    {providers.length === 0 && !error && (
                        <div className="flex flex-col items-center justify-center p-20 bg-white rounded-3xl border-2 border-dashed border-gray-200 text-center">
                            <LayoutGrid size={48} className="text-gray-200 mb-4" />
                            <h3 className="text-xl font-bold text-gray-800">Nenhum serviço de frete</h3>
                            <p className="text-gray-500 max-w-xs mt-2">Adicione transportadoras ou serviços de entrega para começar.</p>
                        </div>
                    )}

                    {providers.map(provider => (
                        <div key={provider.id} className={`bg-white rounded-3xl border-2 transition-all ${editingProvider?.id === provider.id ? 'border-indigo-500 shadow-2xl ring-4 ring-indigo-50' : 'border-gray-100 hover:border-gray-200 shadow-sm'}`}>
                            <div className="p-8 flex flex-col md:flex-row items-center justify-between gap-6">
                                <div className="flex items-center gap-6">
                                    <div className={`w-20 h-20 rounded-2xl flex items-center justify-center transition-colors ${provider.enabled ? 'bg-indigo-50 text-indigo-600' : 'bg-gray-50 text-gray-300'}`}>
                                        <Truck size={32} />
                                    </div>
                                    <div>
                                        <div className="flex items-center gap-3">
                                            <h3 className="text-xl font-black text-gray-800">{provider.name}</h3>
                                        </div>
                                        <p className="text-sm text-gray-400 mt-1 font-medium">Serviço de Logística</p>
                                    </div>
                                </div>

                                <div className="flex items-center gap-4">
                                    <div className="flex flex-col items-end mr-4">
                                        <label className="relative inline-flex items-center cursor-pointer">
                                            <input
                                                type="checkbox"
                                                className="sr-only peer"
                                                checked={provider.enabled}
                                                onChange={() => handleToggle(provider.id, provider.enabled)}
                                            />
                                            <div className="w-14 h-8 bg-gray-200 peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[4px] after:left-[4px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-6 after:w-6 after:transition-all peer-checked:bg-indigo-600"></div>
                                        </label>
                                        <span className={`text-[10px] font-bold mt-1 uppercase tracking-tighter ${provider.enabled ? 'text-indigo-600' : 'text-gray-400'}`}>
                                            {provider.enabled ? 'Operacional' : 'Inativo'}
                                        </span>
                                    </div>
                                    <button
                                        onClick={() => handleOpenConfig(provider)}
                                        className={`px-6 py-2.5 rounded-xl font-bold transition flex items-center gap-2 ${editingProvider?.id === provider.id ? 'bg-gray-100 text-gray-600' : 'bg-indigo-50 text-indigo-600 hover:bg-indigo-100'}`}
                                    >
                                        <Code size={18} /> {editingProvider?.id === provider.id ? 'Fechar' : 'Configurar'}
                                    </button>
                                    <button
                                        onClick={() => handleDelete(provider.id)}
                                        className="p-2.5 text-red-400 hover:text-red-600 hover:bg-red-50 rounded-xl transition"
                                        title="Remover Provedor"
                                    >
                                        <Trash2 size={24} />
                                    </button>
                                </div>
                            </div>

                            {editingProvider?.id === provider.id && (
                                <div className="p-8 pt-0 animate-slide-down space-y-4">
                                    {provider.code === 'MELHOR_ENVIO' ? (
                                        <MelhorEnvioConfig
                                            config={configData}
                                            onChange={setConfigData}
                                        />
                                    ) : provider.code === 'MANDA_BEM' ? (
                                        <MandaBemConfig
                                            config={configData}
                                            onChange={setConfigData}
                                        />
                                    ) : provider.code === 'J3_FLEX' ? (
                                        <J3FlexConfig
                                            config={configData}
                                            onChange={setConfigData}
                                        />
                                    ) : (
                                        <div className="bg-gray-50 p-6 rounded-2xl border border-gray-200 space-y-3">
                                            <label className="text-xs font-bold text-gray-500 uppercase flex items-center gap-2 tracking-widest">
                                                <Code size={14} /> Payload de Configuração (JSONB)
                                            </label>
                                            <textarea
                                                value={JSON.stringify(configData, null, 2)}
                                                onChange={(e) => {
                                                    try { setConfigData(JSON.parse(e.target.value)); } catch (e) { }
                                                }}
                                                className="w-full h-48 p-4 font-mono text-sm border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none shadow-inner"
                                                placeholder='{ "apiKey": "...", "token": "..." }'
                                            />
                                        </div>
                                    )}

                                    <div className="flex justify-end pt-2">
                                        <Button
                                            onClick={handleSaveConfig}
                                            variant="primary"
                                            className="px-8 shadow-lg shadow-indigo-100"
                                        >
                                            <Save size={18} /> Salvar Alterações
                                        </Button>
                                    </div>
                                </div>
                            )}
                        </div>
                    ))}
                </div>
            )}

            {/* Modal de Adicionar Provedor */}
            <BaseModal
                isOpen={isAddModalOpen}
                onClose={() => setIsAddModalOpen(false)}
                title="Novo Provedor de Frete"
                maxWidth="max-w-md"
            >
                <div className="space-y-6">
                    <div className="grid grid-cols-2 gap-3 mb-2">
                        {RECOMMENDED_PROVIDERS.map(p => (
                            <button
                                key={p.code}
                                onClick={() => setNewProvider({ name: p.name, code: p.code, driverKey: p.driverKey })}
                                className={`p-4 rounded-2xl border-2 transition-all text-left flex items-center gap-3 ${newProvider.code === p.code
                                    ? 'border-indigo-600 bg-indigo-50 text-indigo-700'
                                    : 'border-gray-100 hover:border-indigo-200 bg-gray-50'
                                    }`}
                            >
                                <span className="text-2xl">{p.icon}</span>
                                <div>
                                    <div className="font-bold text-[13px]">{p.name}</div>
                                    <div className="text-[10px] opacity-70 uppercase tracking-wider font-mono">{p.code}</div>
                                </div>
                            </button>
                        ))}
                    </div>

                    <div className="space-y-4 pt-4 border-t border-dashed">
                        <div className="space-y-1">
                            <label className="text-sm font-semibold text-gray-600">Nome Transportadora</label>
                            <input
                                type="text"
                                placeholder="Ex: Melhor Envio"
                                className="w-full border p-3 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                                value={newProvider.name}
                                onChange={e => setNewProvider({ ...newProvider, name: e.target.value })}
                            />
                        </div>
                        <div className="space-y-1">
                            <label className="text-sm font-semibold text-gray-600">Código de Serviço</label>
                            <input
                                type="text"
                                placeholder="Ex: MELHOR_ENVIO"
                                className="w-full border p-3 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none uppercase font-mono"
                                value={newProvider.code}
                                onChange={e => {
                                    const code = e.target.value.toUpperCase();
                                    const driverKey = code === 'MELHOR_ENVIO' ? 'shipping.melhorenvio' : code.toLowerCase();
                                    setNewProvider({ ...newProvider, code, driverKey });
                                }}
                            />
                        </div>
                        <div className="space-y-1">
                            <label className="text-sm font-semibold text-gray-600">Driver Key</label>
                            <input
                                type="text"
                                placeholder="Ex: shipping.melhorenvio"
                                className="w-full border p-3 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none font-mono"
                                value={newProvider.driverKey}
                                onChange={e => setNewProvider({ ...newProvider, driverKey: e.target.value })}
                            />
                        </div>
                    </div>

                    <div className="pt-4 border-t flex gap-3">
                        <Button
                            onClick={() => setIsAddModalOpen(false)}
                            variant="secondary"
                            className="flex-1"
                        >
                            Cancelar
                        </Button>
                        <Button
                            onClick={handleAddProvider}
                            disabled={!newProvider.name || !newProvider.code}
                            variant="primary"
                            className="flex-1 shadow-lg shadow-indigo-100"
                        >
                            Criar Provedor
                        </Button>
                    </div>
                </div>
            </BaseModal>
        </div>
    );
}

import { useEffect, useState } from 'react';
import { UserService } from '../../services/UserService';
import type { User } from '../../types/user';
import { UserPlus, Shield, Trash2, Edit } from 'lucide-react';

export function TeamPage() {
    const [users, setUsers] = useState<User[]>([]);
    const [loading, setLoading] = useState(true);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [newUser, setNewUser] = useState({ id: '', name: '', email: '', password: '', role: 'EMPLOYEE' as any });
    const [isEditMode, setIsEditMode] = useState(false);

    useEffect(() => {
        loadUsers();
    }, []);

    const loadUsers = async () => {
        setLoading(true);
        try {
            const data = await UserService.getAll();
            // Exibe apenas membros da equipe (ADMIN e EMPLOYEE)
            const teamOnly = data.filter(u => u.role === 'ADMIN' || u.role === 'EMPLOYEE');
            setUsers(teamOnly);
        } catch (error) {
            console.error('Erro ao carregar usuários', error);
        } finally {
            setLoading(false);
        }
    };

    const handleEdit = (user: User) => {
        setNewUser({ ...user, password: '' } as any);
        setIsEditMode(true);
        setIsModalOpen(true);
    };

    const handleDelete = async (id: string) => {
        if (!confirm('Tem certeza que deseja remover este membro?')) return;
        try {
            await UserService.delete(id);
            loadUsers();
        } catch (error) {
            console.error('Erro ao excluir usuário', error);
            alert('Erro ao excluir usuário.');
        }
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        try {
            if (isEditMode && newUser.id) {
                await UserService.update(newUser.id, newUser);
            } else {
                await UserService.create(newUser);
            }
            setIsModalOpen(false);
            setNewUser({ id: '', name: '', email: '', password: '', role: 'EMPLOYEE' });
            setIsEditMode(false);
            loadUsers();
        } catch (error) {
            console.error('Erro ao salvar usuário', error);
            alert(`Erro ao ${isEditMode ? 'atualizar' : 'criar'} usuário.`);
        }
    };

    return (
        <div className="space-y-6">
            <div className="flex justify-between items-center">
                <div>
                    <h1 className="text-2xl font-bold text-gray-800">Equipe & Permissões</h1>
                    <p className="text-gray-500">Gerencie quem tem acesso à loja</p>
                </div>
                <button
                    onClick={() => { setIsEditMode(false); setNewUser({ id: '', name: '', email: '', password: '', role: 'EMPLOYEE' }); setIsModalOpen(true); }}
                    className="flex items-center gap-2 bg-indigo-600 text-white px-4 py-2 rounded-lg hover:bg-indigo-700 transition"
                >
                    <UserPlus size={20} />
                    Convidar Membro
                </button>
            </div>

            <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
                {loading ? (
                    <div className="p-8 text-center text-gray-500">Carregando equipe...</div>
                ) : (
                    <table className="w-full text-left">
                        <thead className="bg-gray-50 border-b">
                            <tr>
                                <th className="p-4 text-sm font-semibold text-gray-600">Nome</th>
                                <th className="p-4 text-sm font-semibold text-gray-600">Email</th>
                                <th className="p-4 text-sm font-semibold text-gray-600">Função</th>
                                <th className="p-4 text-sm font-semibold text-gray-600">Status</th>
                                <th className="p-4 text-sm font-semibold text-gray-600 text-right">Ações</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-100">
                            {users.length === 0 ? (
                                <tr>
                                    <td colSpan={5} className="p-8 text-center text-gray-500 italic">
                                        Nenhum membro da equipe encontrado.
                                    </td>
                                </tr>
                            ) : (
                                users.map((user) => (
                                    <tr key={user.id} className="hover:bg-gray-50 transition">
                                        <td className="p-4 font-medium text-gray-800 flex items-center gap-3">
                                            <div className="w-8 h-8 rounded-full bg-indigo-100 flex items-center justify-center text-indigo-700 font-bold">
                                                {user.name?.charAt(0) || '?'}
                                            </div>
                                            {user.name}
                                        </td>
                                        <td className="p-4 text-gray-600">{user.email}</td>
                                        <td className="p-4">
                                            <span className={`px-2 py-1 rounded-full text-xs font-bold flex items-center gap-1 w-fit ${user.role === 'ADMIN' ? 'bg-purple-100 text-purple-700' :
                                                user.role === 'EMPLOYEE' ? 'bg-blue-100 text-blue-700' :
                                                    'bg-gray-100 text-gray-700'
                                                }`}>
                                                <Shield size={12} />
                                                {user.role}
                                            </span>
                                        </td>
                                        <td className="p-4 text-sm text-gray-500">
                                            {user.active ? <span className="text-green-600">Ativo</span> : <span className="text-red-500">Inativo</span>}
                                        </td>
                                        <td className="p-4 text-right">
                                            <button
                                                onClick={() => handleEdit(user)}
                                                className="text-gray-400 hover:text-indigo-600 mx-2 transition"
                                            >
                                                <Edit size={18} />
                                            </button>
                                            <button
                                                onClick={() => handleDelete(user.id)}
                                                className="text-gray-400 hover:text-red-600 transition"
                                            >
                                                <Trash2 size={18} />
                                            </button>
                                        </td>
                                    </tr>
                                ))
                            )}
                        </tbody>
                    </table>
                )}
            </div>

            {isModalOpen && (
                <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
                    <div className="bg-white p-6 rounded-lg shadow-lg w-96">
                        <h2 className="text-xl font-bold mb-4">{isEditMode ? 'Editar Membro' : 'Adicionar Membro'}</h2>
                        <form onSubmit={handleSubmit} className="space-y-4">
                            <div>
                                <label className="block text-sm font-medium text-gray-700">Nome</label>
                                <input
                                    type="text"
                                    required
                                    className="w-full border rounded p-2"
                                    value={newUser.name}
                                    onChange={e => setNewUser({ ...newUser, name: e.target.value })}
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-gray-700">Email</label>
                                <input
                                    type="email"
                                    required
                                    className="w-full border rounded p-2"
                                    value={newUser.email}
                                    onChange={e => setNewUser({ ...newUser, email: e.target.value })}
                                />
                            </div>
                            {!isEditMode && (
                                <div>
                                    <label className="block text-sm font-medium text-gray-700">Senha</label>
                                    <input
                                        type="password"
                                        required
                                        className="w-full border rounded p-2"
                                        value={newUser.password}
                                        onChange={e => setNewUser({ ...newUser, password: e.target.value })}
                                    />
                                </div>
                            )}
                            <div>
                                <label className="block text-sm font-medium text-gray-700">Função</label>
                                <select
                                    className="w-full border rounded p-2"
                                    value={newUser.role}
                                    onChange={e => setNewUser({ ...newUser, role: e.target.value as any })}
                                >
                                    <option value="EMPLOYEE">Funcionário</option>
                                    <option value="ADMIN">Administrador</option>
                                </select>
                            </div>
                            <div className="flex justify-end gap-2 mt-4">
                                <button
                                    type="button"
                                    onClick={() => setIsModalOpen(false)}
                                    className="px-4 py-2 text-gray-600 hover:bg-gray-100 rounded"
                                >
                                    Cancelar
                                </button>
                                <button
                                    type="submit"
                                    className="px-4 py-2 bg-indigo-600 text-white rounded hover:bg-indigo-700"
                                >
                                    {isEditMode ? 'Atualizar' : 'Salvar'}
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { Plus, Edit2, Trash2, CheckCircle2, XCircle, Repeat, Package, Percent, Search, Ticket } from 'lucide-react';
import { subscriptionService } from '../../services/subscriptionService';
import { ProductService } from '../../services/ProductService';
import clsx from 'clsx';
import BaseModal from '../../components/ui/BaseModal';
import Button from '../../components/ui/Button';
import { useToast } from '../../context/ToastContext';
import { getImageUrl } from '../../utils/imageUtils';

const INITIAL_PLAN_STATE = {
    type: 'FIXED',
    name: '',
    description: '',
    detailedDescription: '',
    imageUrl: '',
    active: true,
    frequencyRules: [],
    products: [],
    minProducts: 1,
    maxProducts: 10,
    basePrice: 0,
    isCouponPack: false,
    couponBundleCount: 0,
    couponDiscountPercentage: 0,
    couponValidityDays: 0
};

export function SubscriptionPlansPage() {
    const [plans, setPlans] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const [showModal, setShowModal] = useState(false);
    const [editingPlan, setEditingPlan] = useState<any>(INITIAL_PLAN_STATE);
    const [availableProducts, setAvailableProducts] = useState<any[]>([]);
    const [searchTerm, setSearchTerm] = useState('');
    const { addToast } = useToast();
    const [isSaving, setIsSaving] = useState(false);
    const [imageFile, setImageFile] = useState<File | null>(null);
    const [imagePreview, setImagePreview] = useState<string | null>(null);

    useEffect(() => {
        fetchPlans();
        fetchProducts();
    }, []);

    const fetchPlans = async () => {
        try {
            const data = await subscriptionService.getPlans();
            setPlans(data);
        } catch (error) {
            console.error('Erro ao buscar planos:', error);
        } finally {
            setLoading(false);
        }
    };

    const fetchProducts = async () => {
        try {
            const data = await ProductService.getAll();
            setAvailableProducts(data);
        } catch (error) {
            console.error('Erro ao buscar produtos:', error);
        }
    };
    const handleSave = async (e: React.FormEvent) => {
        if (e) e.preventDefault();
        try {
            setIsSaving(true);
            const planToSave = {
                ...editingPlan,
                isCouponPack: editingPlan.type === 'COUPON',
                // Ensure numeric fields are not NaN
                basePrice: Number(editingPlan.basePrice) || 0,
                couponBundleCount: Number(editingPlan.couponBundleCount) || 0,
                couponDiscountPercentage: Number(editingPlan.couponDiscountPercentage) || 0,
                couponValidityDays: Number(editingPlan.couponValidityDays) || 0
            };

            if (editingPlan.id) {
                await subscriptionService.updatePlan(editingPlan.id, planToSave, imageFile || undefined);
                addToast('Plano atualizado com sucesso!', 'success');
            } else {
                await subscriptionService.createPlan(planToSave, imageFile || undefined);
                addToast('Plano criado com sucesso!', 'success');
            }
            fetchPlans();
            setShowModal(false);
            setEditingPlan(INITIAL_PLAN_STATE);
            setImageFile(null);
            setImagePreview(null);
        } catch (error: any) {
            console.error('Erro ao salvar plano:', error);
            addToast('Erro ao salvar plano: ' + (error.response?.data?.message || error.message), 'error');
        } finally {
            setIsSaving(false);
        }
    };

    const toggleProduct = (product: any) => {
        const products = editingPlan.products || [];
        const exists = products.find((p: any) => p.product?.id === product.id || p.productId === product.id);
        let newProducts;
        if (exists) {
            newProducts = products.filter((p: any) => (p.product?.id || p.productId) !== product.id);
        } else {
            newProducts = [...products, { product, productId: product.id, quantity: 1 }];
        }
        setEditingPlan({ ...editingPlan, products: newProducts });
    };

    const updateProductQuantity = (productId: string, quantity: number) => {
        const newProducts = editingPlan.products.map((p: any) =>
            (p.product?.id || p.productId) === productId ? { ...p, quantity: Number(quantity) } : p
        );
        setEditingPlan({ ...editingPlan, products: newProducts });
    };

    const toggleFrequency = (freq: string) => {
        const frequencyRules = editingPlan.frequencyRules || [];
        const exists = frequencyRules.find((r: any) => r.frequency === freq);
        let newRules;
        if (exists) {
            newRules = frequencyRules.filter((r: any) => r.frequency !== freq);
        } else {
            newRules = [...frequencyRules, { frequency: freq, discountPercentage: 0 }];
        }
        setEditingPlan({ ...editingPlan, frequencyRules: newRules });
    };

    const updateDiscount = (freq: string, discount: any) => {
        const newRules = editingPlan.frequencyRules.map((r: any) =>
            r.frequency === freq ? { ...r, discountPercentage: discount === '' ? 0 : Number(discount) } : r
        );
        setEditingPlan({ ...editingPlan, frequencyRules: newRules });
    };

    const filteredProducts = availableProducts.filter(ap => {
        const isNotSelected = !(editingPlan?.products || []).some((p: any) => (p.product?.id || p.productId) === ap.id);
        const productName = ap.title || ap.name || '';
        const matchesSearch = productName.toLowerCase().includes(searchTerm.toLowerCase());
        return isNotSelected && matchesSearch;
    }).slice(0, 15);

    if (loading) return (
        <div className="flex flex-col items-center justify-center p-20 space-y-4">
            <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-indigo-600"></div>
            <p className="text-gray-500 font-medium">Sincronizando planos...</p>
        </div>
    );

    return (
        <div className="space-y-6">
            <div className="flex justify-between items-center">
                <div>
                    <h1 className="text-2xl font-bold text-gray-900">Assinaturas (Ateliê+)</h1>
                    <p className="text-gray-500">Gerencie seus planos de recorrência e combos exclusivos.</p>
                </div>
                <button
                    onClick={() => {
                        setEditingPlan(INITIAL_PLAN_STATE);
                        setShowModal(true);
                    }}
                    className="flex items-center gap-2 bg-indigo-600 text-white px-4 py-2 rounded-lg hover:bg-indigo-700 transition"
                >
                    <Plus size={20} />
                    Novo Plano
                </button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {plans.map(plan => (
                    <div key={plan.id} className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden hover:shadow-md transition">
                        <div className="p-6">
                            <div className="flex justify-between items-start mb-4">
                                <div className={clsx(
                                    "px-2 py-1 rounded text-xs font-bold uppercase tracking-wider",
                                    plan.isCouponPack ? "bg-amber-100 text-amber-700" :
                                        plan.type === 'FIXED' ? "bg-blue-100 text-blue-700" : "bg-purple-100 text-purple-700"
                                )}>
                                    {plan.isCouponPack ? 'Venda de Cupons' : plan.type === 'FIXED' ? 'Fixo (Admin)' : 'Customizado'}
                                </div>
                                {plan.active ? <CheckCircle2 className="text-green-500" size={18} /> : <XCircle className="text-red-500" size={18} />}
                            </div>
                            <h3 className="text-lg font-bold text-gray-900 mb-1">{plan.name}</h3>
                            <p className="text-gray-500 text-sm mb-4 line-clamp-2">{plan.description}</p>

                            <div className="space-y-2 mb-6 text-sm text-gray-600">
                                <div className="flex items-center gap-2">
                                    <Repeat size={16} />
                                    <span>{plan.frequencyRules?.length || 0} frequências configuradas</span>
                                </div>
                                <div className="flex items-center gap-2">
                                    {plan.isCouponPack ? <Ticket size={16} /> : <Package size={16} />}
                                    <span>
                                        {plan.isCouponPack
                                            ? `${plan.couponBundleCount || 0} cupons de ${plan.couponDiscountPercentage || 0}%`
                                            : plan.type === 'FIXED' ? `${plan.products?.length || 0} produtos inclusos` : `${plan.minProducts || 1}-${plan.maxProducts || 10} itens p/ kit`
                                        }
                                    </span>
                                </div>
                                <div className="flex items-center gap-2 font-bold text-indigo-600">
                                    <Percent size={16} className="text-gray-400" />
                                    <span>A partir de R$ {plan.basePrice?.toFixed(2) || '0.00'}</span>
                                </div>
                            </div>

                            <div className="flex gap-2">
                                <Button
                                    onClick={() => {
                                        setEditingPlan({
                                            ...INITIAL_PLAN_STATE,
                                            ...plan,
                                            // Ensure nested arrays are cloned
                                            frequencyRules: plan.frequencyRules ? [...plan.frequencyRules] : [],
                                            products: plan.products ? [...plan.products] : []
                                        });
                                        setImagePreview(plan.imageUrl ? getImageUrl(plan.imageUrl) : null);
                                        setShowModal(true);
                                    }}
                                    variant="secondary"
                                    className="flex-1 py-1"
                                >
                                    <Edit2 size={16} />
                                    Editar
                                </Button>
                                <Button
                                    onClick={async () => {
                                        if (confirm('Excluir plano?')) {
                                            await subscriptionService.deletePlan(plan.id);
                                            addToast('Plano excluído.', 'success');
                                            fetchPlans();
                                        }
                                    }}
                                    variant="secondary"
                                    className="text-red-600 hover:text-red-700 hover:bg-red-50"
                                >
                                    <Trash2 size={18} />
                                </Button>
                            </div>
                        </div>
                    </div>
                ))}

                {plans.length === 0 && !loading && (
                    <div className="col-span-full py-12 text-center bg-white rounded-xl border border-dashed border-gray-300">
                        <Repeat size={48} className="mx-auto text-gray-300 mb-4" />
                        <h3 className="text-lg font-medium text-gray-900">Nenhum plano criado</h3>
                        <p className="text-gray-500">Comece criando um plano fixo ou de cupons para seus clientes.</p>
                    </div>
                )}
            </div>

            <BaseModal
                isOpen={showModal}
                onClose={() => setShowModal(false)}
                title="Configurar Plano de Assinatura"
                maxWidth="max-w-2xl"
            >
                <form onSubmit={handleSave} className="space-y-6">
                    <div className="grid grid-cols-2 gap-4">
                        <div className="space-y-1">
                            <label className="text-xs font-bold text-gray-500 uppercase">Tipo</label>
                            <select
                                value={editingPlan.type || 'FIXED'}
                                onChange={(e) => setEditingPlan({ ...editingPlan, type: e.target.value, isCouponPack: e.target.value === 'COUPON' })}
                                className="w-full border rounded-lg p-2 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none"
                            >
                                <option value="FIXED">Fixo (Admin escolhe)</option>
                                <option value="COUPON">Pacote de Cupons (Venda)</option>
                            </select>
                        </div>
                        <div className="space-y-1">
                            <label className="text-xs font-bold text-gray-500 uppercase">Nome</label>
                            <input
                                type="text"
                                value={editingPlan.name || ''}
                                required
                                onChange={(e) => setEditingPlan({ ...editingPlan, name: e.target.value })}
                                className="w-full border rounded-lg p-2 outline-none focus:ring-2 focus:ring-indigo-500"
                                placeholder="Ex: Combo Axé Mensal"
                            />
                        </div>
                    </div>

                    <div className="grid grid-cols-1 gap-4">
                        <div className="space-y-1">
                            <label className="text-xs font-bold text-gray-500 uppercase">Valor (Preço Base)</label>
                            <div className="relative">
                                <span className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 text-sm">R$</span>
                                <input
                                    type="number"
                                    step="0.01"
                                    value={editingPlan.basePrice || ''}
                                    onChange={(e) => setEditingPlan({ ...editingPlan, basePrice: e.target.value === '' ? 0 : parseFloat(e.target.value) })}
                                    className="w-full border rounded-lg p-2 pl-9 outline-none focus:ring-2 focus:ring-indigo-500"
                                    placeholder="0.00"
                                />
                            </div>
                        </div>
                    </div>

                    <div className="space-y-1">
                        <label className="text-xs font-bold text-gray-500 uppercase">Resumo (Descrição Curta)</label>
                        <textarea
                            value={editingPlan.description || ''}
                            onChange={(e) => setEditingPlan({ ...editingPlan, description: e.target.value })}
                            className="w-full border rounded-lg p-2 outline-none focus:ring-2 focus:ring-indigo-500 min-h-[60px]"
                            placeholder="Breve resumo para o card do plano..."
                        />
                    </div>

                    <div className="space-y-1">
                        <label className="text-xs font-bold text-gray-500 uppercase">Descrição Detalhada</label>
                        <textarea
                            value={editingPlan.detailedDescription || ''}
                            onChange={(e) => setEditingPlan({ ...editingPlan, detailedDescription: e.target.value })}
                            className="w-full border rounded-lg p-2 outline-none focus:ring-2 focus:ring-indigo-500 min-h-[120px]"
                            placeholder="Descreva todos os detalhes, benefícios e o que está incluído no plano..."
                        />
                    </div>

                    <div className="space-y-1">
                        <label className="text-xs font-bold text-gray-500 uppercase">Imagem de Capa</label>
                        <div className="flex items-center gap-4">
                            <div className="relative flex-1">
                                <input
                                    type="file"
                                    accept="image/*"
                                    onChange={(e) => {
                                        const file = e.target.files?.[0];
                                        if (file) {
                                            setImageFile(file);
                                            setImagePreview(URL.createObjectURL(file));
                                        }
                                    }}
                                    className="hidden"
                                    id="plan-image-upload"
                                />
                                <label
                                    htmlFor="plan-image-upload"
                                    className="flex items-center justify-center gap-2 w-full border-2 border-dashed border-gray-200 rounded-lg p-4 cursor-pointer hover:border-indigo-400 hover:bg-indigo-50 transition"
                                >
                                    <Package className="text-gray-400" size={20} />
                                    <span className="text-sm text-gray-500 font-medium">
                                        {imageFile ? imageFile.name : 'Selecionar imagem...'}
                                    </span>
                                </label>
                            </div>
                            {(imagePreview || editingPlan.imageUrl) && (
                                <div className="h-16 w-16 rounded-lg overflow-hidden border bg-gray-50">
                                    <img
                                        src={imagePreview || getImageUrl(editingPlan.imageUrl)}
                                        alt="Preview"
                                        className="w-full h-full object-cover"
                                    />
                                </div>
                            )}
                        </div>
                        <p className="text-[10px] text-gray-400 italic mt-1">* Se não selecionar uma nova imagem, a atual será mantida.</p>
                    </div>

                    {editingPlan.type === 'COUPON' ? (
                        <div className="bg-amber-50 rounded-xl p-4 border border-amber-100 space-y-4">
                            <div className="flex items-center gap-2 text-amber-700 font-bold text-sm">
                                <Ticket size={18} /> Configuração do Pacote de Cupons
                            </div>
                            <div className="grid grid-cols-3 gap-4">
                                <div className="space-y-1">
                                    <label className="text-[10px] font-bold text-amber-600 uppercase">Qtd. Cupons</label>
                                    <input
                                        type="number"
                                        value={editingPlan.couponBundleCount || ''}
                                        onChange={(e) => setEditingPlan({ ...editingPlan, couponBundleCount: e.target.value === '' ? 0 : parseInt(e.target.value) })}
                                        className="w-full p-2 border border-amber-200 rounded-lg outline-none focus:ring-2 focus:ring-amber-500 text-center"
                                        placeholder="0"
                                    />
                                </div>
                                <div className="space-y-1">
                                    <label className="text-[10px] font-bold text-amber-600 uppercase">% Desconto</label>
                                    <input
                                        type="number"
                                        value={editingPlan.couponDiscountPercentage || ''}
                                        onChange={(e) => setEditingPlan({ ...editingPlan, couponDiscountPercentage: e.target.value === '' ? 0 : parseFloat(e.target.value) })}
                                        className="w-full p-2 border border-amber-200 rounded-lg outline-none focus:ring-2 focus:ring-amber-500 text-center"
                                        placeholder="0"
                                    />
                                </div>
                                <div className="space-y-1">
                                    <label className="text-[10px] font-bold text-amber-600 uppercase">Validade (Dias)</label>
                                    <input
                                        type="number"
                                        value={editingPlan.couponValidityDays || ''}
                                        onChange={(e) => setEditingPlan({ ...editingPlan, couponValidityDays: e.target.value === '' ? 0 : parseInt(e.target.value) })}
                                        className="w-full p-2 border border-amber-200 rounded-lg outline-none focus:ring-2 focus:ring-amber-500 text-center"
                                        placeholder="0"
                                    />
                                </div>
                            </div>
                            <p className="text-[10px] text-amber-600 italic">* O cliente receberá {editingPlan.couponBundleCount || 0} cupons de {editingPlan.couponDiscountPercentage || 0}% válidos por {editingPlan.couponValidityDays || 0} dias após cada ciclo de pagamento.</p>
                        </div>
                    ) : (
                        <div className="space-y-4">
                            <div className="flex justify-between items-center">
                                <label className="text-xs font-bold text-gray-500 uppercase">Produtos Selecionados</label>
                                <span className="text-xs text-indigo-600 border border-indigo-100 bg-indigo-50 px-2 py-0.5 rounded-full">Soma do Admin</span>
                            </div>

                            <div className="space-y-2 max-h-[200px] overflow-y-auto pr-1 custom-scrollbar border rounded-xl p-2 bg-gray-50/50">
                                {(editingPlan.products || []).map((p: any) => (
                                    <div key={p.product?.id || p.productId} className="flex items-center justify-between p-2 bg-white rounded-lg border border-gray-100 shadow-sm">
                                        <div className="flex items-center gap-3 min-w-0">
