                                const rule = frequencyRules.find((r: any) => r.frequency === freq.key);
                                return (
                                    <div key={freq.key} className="flex flex-col gap-1">
                                        <button
                                            type="button"
                                            onClick={() => toggleFrequency(freq.key)}
